const GROUPS = [{"group":"专注 · 注意力","items":[{"code":"F01","title":"多巴胺不是快乐物质","sub":"你以为的\"快乐\"，其实是\"想要\"","color":"coral","id":"02-dopamine"},{"code":"F02","title":"短视频为什么刷不完","sub":"它被设计成\"刷不完\"的","color":"coral","id":"03-variable-reward"},{"code":"F03","title":"注意力被切碎，到底亏了什么","sub":"一直切来切去，代价有多大","color":"coral","id":"04-switching-cost"},{"code":"F04","title":"注意力是你唯一真正拥有的","sub":"为什么刷完反而更累","color":"coral","id":"01-attention-scarce"},{"code":"F05","title":"识字，不等于会用文字","sub":"短视频正在抹掉你用文字的能力","color":"coral","id":"05-power-of-words"},{"code":"F06","title":"用它做这个，就不能做那个","sub":"别硬忍，用好习惯把坏习惯挤出去","color":"coral","id":"06-opportunity-cost"},{"code":"F07","title":"你最该专注的，可能不是作业","sub":"睡眠、运动、放松，才是给大脑充电","color":"blue","id":"07-brain-battery"},{"code":"F08","title":"这件事，值我一生的万分之一吗","sub":"一把随身的尺子：值不值得专注","color":"green","id":"08-worth-it"}]},{"group":"把时间当作朋友","items":[{"code":"T01","title":"你不是大脑的奴隶","sub":"谁主谁仆","color":"blue","id":"09-master-or-servant"},{"code":"T02","title":"时间，其实管不了","sub":"能管的不是时间，是你自己","color":"green","id":"10-time-unmanageable"},{"code":"T03","title":"没有捷径，只有交换","sub":"你越想快，越快不了","color":"coral","id":"11-accept-reality"},{"code":"T04","title":"你的时间，到底去哪了","sub":"一支笔，看清时间花在哪","color":"blue","id":"12-time-log"},{"code":"T05","title":"没人教你的时候，你还学得会吗","sub":"自学，是能学会任何东西的元能力","color":"green","id":"13-self-learning"},{"code":"T06","title":"三个思维陷阱，大多数人天天中招","sub":"反过来不一定成立 · 相关不等于因果 · 自证预言","color":"coral","id":"14-thinking-traps"},{"code":"T07","title":"会听的人，其实很少","sub":"听，是决定你能走多远的隐形能力","color":"blue","id":"15-listening"},{"code":"T08","title":"积累不是加法，是乘法","sub":"10万本金10%利率30年后是174.5万，不是40万","color":"green","id":"16-compound-interest"}]},{"group":"学习的真相","items":[{"code":"L01","title":"学习，只不过是读说明书","sub":"路标、药品、软件帮助——说明书无所不在，只是没人读","color":"green","id":"17-read-the-manual"},{"code":"L02","title":"不练的手，不属于你的大脑","sub":"大脑是一张网：学得越多学得越快；不用即弃","color":"coral","id":"18-use-it-or-lose-it"},{"code":"L03","title":"过目不忘，是编出来的","sub":"记忆的核心不是信息，而是关联——记得越多，记得越快","color":"blue","id":"19-memory-capacity"},{"code":"L04","title":"你看到的，是大脑猜出来的","sub":"大脑用最熟悉的模型做预测——学习就是习得、应用、改良、构建模型","color":"green","id":"20-model-matching"},{"code":"L05","title":"入门需要的，比你想的少","sub":"MAKE 最少必要知识：清单短得惊人——学会就马上开始用","color":"coral","id":"21-minimal-knowledge"},{"code":"L06","title":"复杂的本事，拆开都是流程","sub":"顺序·循环·分支——习惯是最简单的流程；删不掉旧路，只能盖一条更宽的新路","color":"blue","id":"22-habit-is-process"},{"code":"L07","title":"计划，只需要计划复习","sub":"课程表列满任务成效却差——真正有效的计划只做复习；判断依据=一张可修订的检查表","color":"green","id":"23-plan-review"},{"code":"L08","title":"越往前学，越容易","sub":"卡住不是因为笨——隐含关联、复合技能、前置引用；唯一解法是继续往前学","color":"coral","id":"24-stuck"},{"code":"L09","title":"从一开始，就当生产者","sub":"世界只有两种人：消费者和生产者——生产者从第一天起，就只以创造为目标","color":"blue","id":"25-be-a-producer"},{"code":"L10","title":"烧水的时候，把杯子洗了","sub":"统筹只研究串联和并联——节省时间的核心来自并联；学习就是攒时间","color":"green","id":"26-overall-planning"}]},{"group":"思考的真相","items":[{"code":"K01","title":"你脑子里有一张概念表","sub":"思考的核心是概念——定义只是一个等号：左边要必要，右边要毫无歧义","color":"coral","id":"27-define-it"},{"code":"K02","title":"不重不漏，才算想全了","sub":"良好分类只有两条：合理=子类别互不重合，完整=加起来等于全部——\"思考全面\"不过如此","color":"blue","id":"28-sort-it-out"},{"code":"K03","title":"选不出来，是因为还没比完","sub":"可比=同一范畴+相同属性；依据要客观可量化——多个依据给权重算总分，比较结果一出，决策呼之欲出","color":"green","id":"29-compare-it"},{"code":"K04","title":"先发生的，不一定是原因","sub":"时间先后不保证因果——因果分析几乎是整个科学的核心；普通人的够用工具＝四问：是原因吗·唯一吗·还有哪些·哪个最重要","color":"coral","id":"30-trace-the-cause"},{"code":"K05","title":"决策，不是第五种本领","sub":"每个决策背后，全是定义→分类→比较→因果的组合应用——流水线第一步（定义）不同，终点（决策）就完全不同","color":"blue","id":"31-decide-it"},{"code":"K06","title":"世界不是一根因果链","sub":"冰淇淋和溺水一起涨落，只因共同原因是天气热——真实世界是一因多果、一果多因、互为因果，由时间穿起来的三维因果系统","color":"green","id":"32-cause-web"},{"code":"K07","title":"约等号，是一座桥","sub":"类比=在陌生的 x 和熟悉的 a 之间画一个约等号，跨越已知与未知的鸿沟——但 ≈ 不是 ＝；反过来用就是举一反三：这个道理还能用在什么地方？","color":"coral","id":"33-analogy"}]}];
const CONTENT = {"02-dopamine":{"id":"02-dopamine","kicker":"成长读本 · 关于注意力","title":"多巴胺不是快乐物质","hook":"你有没有发现：游戏、短视频刷得停不下来，\n 可刷完之后，不是更开心，而是有点空、有点烦。\n 这不是错觉——你的大脑给你的，根本不是\"快乐\"。","sections":[{"h3":"1它给的是\"想要\"，不是\"快乐\"","paras":["多巴胺是大脑里的一种化学物质。上世纪 50 年代刚发现它时，科学家给小老鼠装上电极，老鼠就疯狂按按钮、不吃不喝，于是被误以为是\"快乐物质\"。","但真相是：多巴胺制造的是\"想要\"的冲动。真正的\"爽快感\"，是另外几种物质（内啡肽、催产素、血清素）带来的。想要 ≠ 快乐——这是两套系统。"],"art":"data:image/svg+xml;base64,","caption":"\"想要\"和\"快乐\"由不同物质负责"},{"h3":"2真正点燃它的，是\"也许有惊喜\"","paras":["多巴胺不是被确定的奖励触发的，而是被\"惊喜的可能性\"触发的。大脑一直在预测下一刻，当结果比预想的更好（一次愉快的\"预测错误\"），它就记住，并在下次产生期待。","这正是刷视频、抽卡、刷新页面让人停不下来的原因：下一条，也许更好看。不确定，才最勾人。"],"art":"data:image/svg+xml;base64,","caption":"不确定的\"可能惊喜\"，让多巴胺冲到最高"},{"h3":"3爽感越来越短，冲动还在","paras":["就算真有快感，它也有两个毛病：消失得越来越快，而且一次比一次弱，直到归零。可制造\"想要\"的冲动并不会跟着停。","所以那只老鼠并不是\"爽死\"的，是被冲动累死的——而且在累死前的很长时间里，它其实一直烦躁不安。停不下来的你，和它是同一套机制。"],"art":"data:image/svg+xml;base64,","caption":"快感趋零，\"还想要\"却不停——于是停不下来"},{"h3":"4系统会\"被劫持\"","paras":["原本这套机制很精巧：它推动人类去探索、去进步。问题是，手机给了你一个随时能按的\"按钮\"——可变的、即时的、永远刷不完的惊喜。于是多巴胺系统被劫持，你成了那只按按钮的老鼠。","看清这一点，不是为了自责。那是化学反应，不是你不够自律。看懂它，你才有机会把按钮放下。"],"art":null,"caption":""}],"quote":"\"多巴胺刺激的是冲动，把它叫做快乐物质，错得有点离谱。\"","quoteSrc":"—— 《专注的真相》","reflect":[{"q":"上一次你\"停不下来\"地刷，是因为很快乐，还是因为停不下来？","hint":"没有标准答案。试着分清\"我享受它\"和\"我被它推着走\"。"},{"q":"什么事会让你做完之后感到踏实满足，而不是\"还想要更多\"？","hint":"那类事，往往动用的是\"满足感\"系统，而不是\"想要\"系统。"}],"actionTitle":"🎯 行动卡 · 本周","action":"下次伸手要刷手机时，先做一个\"2 分钟暂停\"：等两分钟，问自己一句——\"我现在是想要快乐，还是被冲动推着？\"两分钟后还想刷，就刷；但记下来：有几次，两分钟一过其实就不那么想了？"},"03-variable-reward":{"id":"03-variable-reward","kicker":"成长读本 · 关于注意力","title":"刷视频，为什么停不下来？","hook":"赌场里的老虎机是全世界最赚钱的机器之一。\n 设计它的人，用的是一个已经研究了七十年的心理学秘密——\n 你的手机 App，用的是同一套。","sections":[{"h3":"1斯金纳的鸽子实验","paras":["1950 年代，心理学家斯金纳做了一个实验：训练鸽子按按钮拿食物。他对比了两种设定：","固定奖励——每按 10 次必给一粒食物。鸽子学会了，但按到规律后就慢下来，够吃就停。","可变奖励——随机给，有时 3 次，有时 20 次，不知道哪次有。鸽子疯了：按按钮的频率是固定奖励组的 3 倍以上，即使把食物撤掉，还能狂按几百次。","这就是可变奖励的力量——不确定，反而让人更难停。"],"art":"data:image/svg+xml;base64,","caption":"不确定性让\"想要\"系统一直处于高度激活状态"},{"h3":"2短视频就是手机里的老虎机","paras":["老虎机的核心设计：你不知道下一次拉杆会是大奖还是没有。这个不确定性，让你停不下来。","短视频做了同一件事：每次上划，你不知道会刷到无聊内容还是绝好笑的视频。平台用算法精确控制这个比例——足够多的\"好内容\"让你留下，足够多的\"普通内容\"让你期待下一个。","设计这套系统的人，有时公开承认他们研究过赌博心理学。这不是巧合，这是意图。"],"art":"data:image/svg+xml;base64,","caption":"机制相同，只是把\"拉杆\"换成了\"上划\""},{"h3":"3无限滚动：把终点抹掉了","paras":["老虎机还有一个致命设计：它没有终点。你可以无限拉下去，直到钱花完。","短视频的\"无限滚动\"（Infinite Scroll）是同一回事。早期的互联网页面有\"下一页\"按钮，那个按钮是一个自然的停顿点——让你有机会决定是否继续。无限滚动把这个停顿点抹掉了。","发明无限滚动的工程师后来公开表示，他对自己发明的这个功能感到后悔。"],"art":null,"caption":""},{"h3":"4看清它，是为了不被它牵着走","paras":["这不是说你不能刷视频。这是说：你现在知道了，那个\"再刷一个\"的冲动，是被设计出来的，不是你真正想要的。","赌场赢钱靠的是：你在状态里就忘了算钱。短视频赢的是：你在状态里就忘了时间。","有意识地主动给自己设定一个终点——比如提前决定看几条、看几分钟——你就把那个被抹掉的\"停顿点\"还给了自己。"],"art":null,"caption":""}],"quote":"\"那些被设计出来抢夺注意力的产品，用的都是真实的、已被验证的心理学机制。\"","quoteSrc":"—— 《专注的真相》","reflect":[{"q":"上次刷视频，你是在\"主动选\"看什么，还是被算法推着走？","hint":"两种体验是完全不同的。\"主动选\"需要你先有一个目的；\"被推着走\"的状态里，目的是算法替你决定的。"},{"q":"如果你给自己设定\"只看 5 分钟\"，到时间后是什么感觉？比没有限制的时候累还是轻松？","hint":"这个实验结果会告诉你很多。很多人发现，有边界反而更享受——因为享受的是内容，不是\"也许下一个更好\"的焦虑。"}],"actionTitle":"🎯 行动卡 · 本周","action":"选一天，刷短视频前先在心里或纸上定好\"今天只看 10 分钟\"，到时间就停。记录一下：定了限制之后，刷的时候和刷完之后的感受，和平时有什么不同？"},"04-switching-cost":{"id":"04-switching-cost","kicker":"成长读本 · 关于注意力","title":"注意力被切碎，到底亏了什么","hook":"你有没有过这种晚上：一边写作业，\n 手机\"叮\"一声就切过去看一眼，再切回来——\n 切了几十次，作业没写多少，人却累得不行。","sections":[{"h3":"1每次\"切一下\"，都要交一笔费","paras":["注意力不是水龙头，说开就开、说关就关。你刚沉进一件事，脑子里装着前因后果；一被打断切走，这些就散了。等你切回来，得从头把它们重新\"装载\"一遍——这段重新进入的时间，就是切换的成本。","所以同样一个小时，\"一直切来切去\"和\"安安静静做一件事\"，产出可以差很多。不是你笨，是时间被一次次切换悄悄抽掉了。"],"art":"data:image/svg+xml;base64,","caption":"同样长的一段时间，切换越多，真正做事的部分越少（示意）"},{"h3":"2身边\"永远在线\"的屏幕，越来越多","paras":["为什么我们会忍不住一直切？因为每一块亮着的屏幕，都是一次\"切一下\"的邀请。《专注的真相》的作者数了数自己身边的屏幕：两部手机、一部安卓机、一个 iPad、一台笔记本、两台台式机（还外接一块显示器）、客厅卧室工作室各一台电视——加起来 11 块，开车时特斯拉中控还得再算一块。","这不是他一个人的特殊情况，今天几乎人人如此。屏幕越多，邀请越多，注意力被切碎得也越碎。"],"art":"data:image/svg+xml;base64,","caption":"每一块亮着的屏，都是一次\"切过来看看\"的邀请"},{"h3":"3最坑的地方：你感觉不到","paras":["如果摔一跤骨折了，你会疼、会肿、会知道要去看医生。可大脑是一个藏在里面的器官——长期被短视频这类东西反复\"劫持\"，它会发生真实的、不容易逆转的变化，但你不疼不痒，自己根本察觉不到。","正因为感觉不到，很多人会以为\"我就是刷会儿手机，没事\"。书里把这件事说得很重：这不只是个坏习惯，它是在悄悄改变你大脑的结构。看不见，不等于没发生。"],"art":"data:image/svg+xml;base64,","caption":"大脑受了影响，自己往往无从知晓"},{"h3":"4一组真实的数据","paras":["这不是吓唬人。美国疾控中心的数据显示，被诊断为多动症（ADHD，一种典型的注意力缺乏症状）的儿童比例，从 2003 年的将近 8% 升到 2011 年的 11%——而这段时间，正好是移动互联网快速铺开的时候。","按年龄看，发病率的增幅更明显：越大的孩子，涨得越多。注意力变难，是真的正在发生的事。"],"art":"data:image/svg+xml;base64,","caption":"各年龄段多动症发病率的增幅（数据来源：美国疾控中心，《专注的真相》引用）"}],"quote":"\"大脑是看不见、摸不着的器官——如果它受伤了，我们自己并不知道，甚至无从知晓。\"","quoteSrc":"—— 《专注的真相》","reflect":[{"q":"昨天你认真做一件事的时候，被\"切走\"过几次？是它来找你，还是你去找它？","hint":"没有标准答案。分清\"被打扰\"和\"主动去刷\"，是夺回注意力的第一步。"},{"q":"你身边有几块\"永远在线\"的屏幕？哪一块是你现在就能关掉、或挪走的？","hint":"不用全关。少一块亮着的屏，就少一份\"切一下\"的邀请。"}],"actionTitle":"🎯 行动卡 · 本周","action":"挑一个晚上，做一次\"单线程实验\"：做一件事时，把手机调静音、放到另一个房间，做完再回去看。结束后记两个数字——这一晚你想切走几次，以及真正去切了几次。下次再做，看能不能把第二个数字压小一点。"},"01-attention-scarce":{"id":"01-attention-scarce","kicker":"成长读本 · 关于注意力","title":"注意力是你唯一真正拥有的","hook":"你有没有过这种事：打开手机本来想查一道题，\n 十分钟后抬起头，忘了自己要查什么，\n 但已经刷了三个视频。这不是你不自律。","sections":[{"h3":"1什么是\"注意广度\"","paras":["注意广度，就是你被一件事吸引之后，能连续保持专注多久。它是一切深入活动的地基——没有它，学习、思考、做事都谈不上。","一个有点吓人的对比：2008 年的研究里，三岁孩子的平均注意广度大约是 1.8 分钟。而今天，很多成年人的注意广度，其实也已经不到两分钟了。"],"art":"data:image/svg+xml;base64,","caption":"注意广度：被吸引后还能专注多久"},{"h3":"2为什么它越来越\"贵\"","paras":["1971 年，一位叫西蒙的学者说过一句很准的话：信息越丰富，注意力就越稀缺。因为信息要被\"消费\"，而它消费掉的，正是你的注意力。","过去，人和人之间最大的差距是钱；后来是知识。而现在以及将来，最大的差距，是注意力上的\"贫富差距\"——谁能专注更久，谁就能学到、做到、创造出别人做不到的东西。"],"art":"data:image/svg+xml;base64,","caption":"人和人最大的差距，正在变成注意力"},{"h3":"3有个门槛：20 分钟","paras":["真正有意义的事——认真学一段、想清一个问题、好好练一次、复盘一次——都需要一段足够长的连续专注。番茄钟把它定在大约 20 分钟。","换句话说：如果你的专注总是被打断在 20 分钟以内，那段时间几乎等于白过。不是你不努力，是注意力没攒够到能\"起作用\"的长度。"],"art":"data:image/svg+xml;base64,","caption":"专注时长一旦越过门槛，价值才真正出现"},{"h3":"4\"知识的山峰\"","paras":["人类的知识大约每 18 个月就翻一倍（这被叫做\"知识摩尔定律\"）。这座\"知识的山峰\"过去像个小土包，谁都能爬到半山腰；现在越来越高、越来越陡。","山顶永远有人能到，因为山本来就是人一点点堆出来的。但能爬上去的人比例会越来越小。而注意广度只有两分钟的人，只能留在山脚下。选哪一头，很大程度上由你能专注多久决定。"],"art":"data:image/svg+xml;base64,","caption":"山越来越陡，登顶靠的是能专注多久"}],"quote":"\"人与人之间最大的差异，是注意力上的贫富差距。\"","quoteSrc":"—— 《专注的真相》","reflect":[{"q":"过去这一周，你最专注的一段时间在做什么？大概多久？","hint":"没有标准答案。如果想不起任何超过 20 分钟的时刻，这本身就是个有用的发现。"},{"q":"哪些东西最常把你的专注\"切断\"？是它们找你，还是你去找它们？","hint":"分清\"被打扰\"和\"主动去刷\"，往往是夺回注意力的第一步。"}],"actionTitle":"🎯 行动卡 · 本周","action":"挑一天，做一次\"25 分钟实验\"：选一件你真想做好的事，把手机放到另一个房间，只做这一件事 25 分钟。结束后记一句话：这 25 分钟和平时被切碎的时间，感觉有什么不同？"},"05-power-of-words":{"id":"05-power-of-words","kicker":"成长读本 · 关于注意力","title":"识字，不等于会用文字","hook":"一个有点扎心的问题：\n 你上一次安安静静读完一篇两三千字的长文，\n 是什么时候？想不起来，并不只是你一个人。","sections":[{"h3":"1文字，是人类偷偷点出的\"超能力\"","paras":["几乎所有动物都有自己的\"语言\"：蜜蜂跳八字舞，小鸟叽叽喳喳，海豚吹哨。但只有人类，除了用声音说，还能用文字记下来。","说话有两个天生的限制：声音再大也传不远，话音一落就消失。文字把这两个限制都打破了——它能传到很远的地方，也能留到很久以后。所以今天的你，还能读到孔子、苏格拉底两千多年前说过的话。经验能跨过一代代人往下传，这是地球上其他物种都做不到的事。"],"art":"data:image/svg+xml;base64,","caption":"声音受空间和时间限制；文字两样都能突破（示意）"},{"h3":"2\"识字\"和\"会用文字\"，是两回事","paras":["真正用文字的人，每天做两件事：用文字输入（读），用文字输出（写）。一个人如果识字，却既不读也不写，那从行为上看，和不识字的人其实没差别——书里说得很直接。","大量刷短视频的人，正悄悄变成这样：输入是画面和声音，输出是手指滑一下、点个赞。整个过程，几乎用不到文字。"],"art":"data:image/svg+xml;base64,","caption":"识字却不读不写，行为上和文盲并无两样（《专注的真相》）"},{"h3":"3大脑也\"用进废退\"","paras":["读一段有点难度的文字，你的大脑得调动注意力、调动口舌和手指去配合、去思考——它在被使用。而刷短视频时，每一分每一秒大脑都是被动接收，那些精密的协调几乎全程闲置。","肌肉不练会萎缩，大脑也一样：常用的部分变强，长期不用的部分会退化。所以\"刷一会儿放松一下\"和\"用文字想清楚一件事\"，对大脑来说是两个相反的方向。"],"art":"data:image/svg+xml;base64,","caption":"同样的时间，方向不同，大脑走向相反"},{"h3":"4最麻烦的是：它会越滚越快","paras":["注意广度（能专注的时长）一旦变短，自制力就会跟着变差；自制力越差，就越容易被短视频吸住；越被吸住，注意广度就更短……这是一个往坏处转的飞轮，自己转起来，很难停。","书里给了个参考：注意广度低于 20 分钟，基本就没法做任何有意义的阅读了。而很多人现在，大概只剩下两分钟。好消息是——这个飞轮也能反过来转：每多用一次文字，就给它一个反方向的推力。"],"art":"data:image/svg+xml;base64,","caption":"负向飞轮：短→差→更短。反过来用文字，就能给它逆向的力"}],"quote":"\"一定要重视文字，善用文字。\"","quoteSrc":"—— 《专注的真相》（这句书里重复了很多遍）","reflect":[{"q":"今天你\"用文字\"和\"刷画面\"的时间，大概各是多少？哪个更长？","hint":"没有标准答案。先看清比例，再决定要不要调一调。写在你自己的本子上。"},{"q":"有没有一件你想清楚的事，是看视频看不会、必须读和写才能弄明白的？","hint":"越复杂、越抽象的东西，越要靠文字才装得下。这正是文字最值钱的地方。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一个\"用文字\"的小练习：每天挑一件当天发生的事，或读到的一段话，用三到五句完整的话把它写下来——不是发给谁，就写给自己。坚持一周，回头看看：你能不能比第一天，写得更清楚一点、更长一点？"},"06-opportunity-cost":{"id":"06-opportunity-cost","kicker":"成长读本 · 关于注意力","title":"用它做这个，就不能做那个","hook":"先想一件怪事：\n \"我不要再刷手机了\"——这句话你说过很多次，做到却很难。\n 但\"我今天不去操场踢球\"，你几乎从来不用咬牙忍。同样是不去做一件事，差别为什么这么大？","sections":[{"h3":"1时间和注意力，是\"排他性资源\"","paras":["钱有一个特点：同一笔钱，买了这个就买不了那个。书里说，时间、精力、注意力、意志力也一样——它们都是\"排他性资源\"，用它来做这件事，就不能再用它去做那件事。","所以你的一天，不是一个可以无限装东西的口袋。它更像一个固定大小的杯子：装满了有用的，就没地方装没用的；反过来也一样。"],"art":"data:image/svg+xml;base64,","caption":"同一只杯子，装了 A 就没空间给 B（示意）"},{"h3":"2\"忍住别做\"，本身就特别费劲","paras":["回到开头那件怪事。你不用忍住不踢球，是因为你本来就没特别想踢；而你要忍住不刷手机，是因为手机被设计得让你一直想。于是你得时时刻刻按住那个冲动。","书里点破了关键：克制和控制，是相当耗费整体脑力的。你真正的对手，不是某一段视频，而是\"持续克制\"这件事本身——它会把你的意志力一点点磨光。光靠\"我要忍住\"，多半会输。"],"art":"data:image/svg+xml;base64,","caption":"越用力克制，越早耗光——这不是你不够自律"},{"h3":"3换个打法：用好习惯，把坏习惯挤出去","paras":["书里给了一句反直觉的话：纵容好习惯，会有效地抑制坏习惯。意思是——别正面跟坏习惯死磕，去喂养一个好习惯，让它把资源占满。","作者讲过一个真实例子：很多人都知道乱花钱不好，可就是忍不住。直到有一天他们发现钱还有\"投资\"这个用法，开始投资之后，消费的欲望竟然自己消失了——不需要克制、不需要节制，毫不费力。因为更好的用法，把更差的用法挤出去了。"],"art":"data:image/svg+xml;base64,","caption":"把杯子用更好的东西装满，更差的东西自己就溢出去了"},{"h3":"4前提：你得先知道\"什么更值得\"","paras":["这套打法有一个前提：你得分得清，什么好、什么差、什么和什么比起来更值得。好钢要用在刀刃上——可前提是，你知道哪儿是刀刃。","书里举了两个特别具体的\"占满注意力\"的好东西：一是户外运动，尤其是跑步（跑起来那半小时，你根本没法刷手机，还顺带保护视力）；二是学编程（让机器听你的话，这件事本身太迷人，注意力会被它牢牢占住）。它们的共同点是：不靠\"少刷\"，而是给你一件更想做的事。"],"art":"data:image/svg+xml;base64,","caption":"挑你\"真心想做\"的那一件，把时间先占住（《专注的真相》举例）"}],"quote":"\"纵容好习惯，会有效地抑制坏习惯。\"","quoteSrc":"—— 《专注的真相》：一旦把时间、精力、注意力用在更好的地方，就不大可能剩下什么去用在更差的地方。","reflect":[{"q":"你最想戒掉的那个习惯，如果不靠\"忍\"，有没有一件更想做的事能顶上它的时间？","hint":"没有标准答案。先别想\"少做什么\"，先想\"多做什么\"。写在你自己的本子上。"},{"q":"你这一周里，哪段时间是\"硬忍\"撑过去的？换成\"被一件好事占住\"，会不会轻松一点？","hint":"硬忍会耗光意志力；被占住几乎不费劲。它们走向相反的结果。"}],"actionTitle":"🎯 行动卡 · 本周","action":"挑一件你\"一直说想做、却总说没时间\"的事（运动、写代码、读一本书都行），给它固定一段时间，比如每天放学后的半小时。这一周，不去刻意\"少刷手机\"——只是先把那半小时占住。一周后回头看：你刷的时间，是不是自己变少了？"},"07-brain-battery":{"id":"07-brain-battery","kicker":"成长读本 · 关于注意力","title":"你最该专注的，可能不是作业","hook":"问你一个排序题：\n 手机天天在抢你的注意力——你觉得它最先伤到的，是哪件事？\n 大多数人会脱口而出：\"学习和工作。\"书里说，这个答案，恰恰排错了顺序。","sections":[{"h3":"1你的大脑，是一块每天都在耗电的电池","paras":["书里给了一个特别准的比喻：大脑是人体最耗能的器官。上千亿个脑细胞同时工作，神经元之间靠\"放电\"沟通——这不是打比方，是和真实电网一样的放电。","所以你每天都在耗电。可怪事来了：人对手机的电量焦虑到能撑起一门租充电宝的生意，却对自己大脑的电量毫不在意。一旦缺电，CPU 再快、内存再大也没用，作业、考试、连过日子都会变糟。"],"art":"data:image/svg+xml;base64,","caption":"大脑耗电远超手机，却几乎没人为它\"充电焦虑\"（《专注的真相》）"},{"h3":"2真正的优先顺序：先充电，再干活","paras":["那被手机干扰的事，到底该按什么顺序排重要性？书里给出的答案，可能和你想的完全相反：","看出门道了吗？排在最前面的三件——睡眠、运动、放松——大多数人压根没把它们当成\"要专注去做的事\"。可它们才是给电池充电、扩容、优化的环节。电池没顾好，后面的学习和工作，都是带着半格电硬撑。"],"art":"data:image/svg+xml;base64,","caption":"差不多一小时运动，对大脑既是充电、又是维护、还是扩容（《专注的真相》）"},{"h3":"3最隐蔽的漏电口：睡前那几十分钟手机","paras":["\"睡前刷几十分钟手机，再把它放在枕边睡觉\"——书里说，这已经是至少 99.99% 的人的习惯。看着不起眼，对睡眠的打击却很重。","眼睛睡前暴露在屏幕蓝光下，深度睡眠的时长会缩短至少四分之一；而且它会让你不知不觉睡得越来越晚，雪上加霜。更狠的是：一次睡不好，会拖累接下来两三天的效率。一个小动作，漏掉的是好几天的电。"],"art":"data:image/svg+xml;base64,","caption":"把手机放出卧室，是给大脑充满电最便宜的办法"},{"h3":"4练专注，不一定靠冥想","paras":["说到练注意力，几乎所有书都推荐冥想。书里却说：其实有更好上手的办法。冥想是关闭各种器官、只盯住一处；而朗读、弹唱、跑步走的是相反的路——同时调动、协调更多器官，让外界根本插不进来。","两条路殊途同归：都会让你不由自主地高度专注，同时身体超级放松，时间一晃就过去——这就是人们常说的\"心流\"。它们的共同好处是：你不用咬牙逼自己专注，是被这件事自然吸住的。爱因斯坦拉小提琴、达·芬奇样样通，不是巧合。"],"art":"data:image/svg+xml;base64,","caption":"选一件真心喜欢、又得动用多个器官的事，专注会自己找上门"}],"quote":"\"大脑时时刻刻都在耗电，所以你必须拥有一个更大容量的电池。\"","quoteSrc":"—— 《专注的真相》：睡眠是充电，运动是扩容，放松是优化。这三件，都值得你刻意专注去做。","reflect":[{"q":"如果给昨天的自己排个顺序：睡眠、运动、放松、学习——你实际花的时间，是按什么顺序排的？","hint":"没有标准答案。你\"做\"的顺序，往往才是你真正的价值观。写在你自己的本子上。"},{"q":"你有没有一件\"做着做着时间就没了\"的事？那很可能就是属于你的心流活动。","hint":"那种\"一晃几小时、又累又轻松\"的体验，正是大脑在健身房里撸铁。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一个五天小实验：睡前 30 分钟，把手机放到卧室外面充电（不是枕边、不是抽屉，是另一个房间）。每天早上花十秒给自己的精神打个分（1–10）。五天后回看那串分数——你会发现，让你白天更清醒的，可能不是多刷的题，而是没被偷走的那段深睡。"},"08-worth-it":{"id":"08-worth-it","kicker":"成长读本 · 关于注意力","title":"这件事，真的值我一生的万分之一吗？","hook":"你大概觉得，一辈子七八十年，时间多得是。\n 可如果把睡觉、上学、吃饭、刷手机这些都扣掉，真正能由你自己说了算的时间，可能只剩 9 年。\n 书里把这 9 年切成一万份，给了你一把随身的尺子。","sections":[{"h3":"1先算一笔账：你的时间，去哪了","paras":["书里按平均寿命 78 年算了一笔账，结果挺扎心：睡觉就花掉约 28 年，能拿出来工作的时间只有 10 来年，而刷各种社交媒体的时间，居然有 9 年——比你这辈子真正\"接受教育\"的 3.5 年还多。","一项项扣下来，真正由你自由支配的时间，只剩下大约 9 年。78 年里，只有 9 年是你自己的。"],"art":"data:image/svg+xml;base64,","caption":"78 年里，真正可由你自由支配的，只有约 9 年（《专注的真相》）"},{"h3":"2把一生，折算成一万份","paras":["9 年大约是 3285 天。书里说，要是按 1/3285 来算每件事的分量，未免太苛刻；可要是说\"人这一生大概三万天\"，又听着太阔绰。于是他折中——用万分之一。","这就有了一个特别简单、又特别狠的尺子：\"今天我要做的这件事，真的值我一生的万分之一吗？\" 一旦你心里有了这把尺，就很难再大手大脚地花时间了。"],"art":"data:image/svg+xml;base64,","caption":"把\"很多\"变成\"一份\"，模糊的时间就有了可以掂量的重量"},{"h3":"3一件事的成本，不只是钱","paras":["书里提醒：做任何事的成本，不仅仅是金钱。还有时间成本——它一去不回；最紧张的，是注意力成本。你要主动调用注意力，还要想办法不让它被夺走，再克服各种困难和意外。","钱花光了还能再赚，时间和注意力却是真的\"用此即弃彼\"。所以这把尺子量的，其实是你最贵的那一项。"],"art":"data:image/svg+xml;base64,","caption":"看清成本里还藏着时间和注意力，你就不敢\"大手大脚\"了（《专注的真相》）"},{"h3":"4同一把尺，也能用来\"识人\"","paras":["有意思的是，这把尺子不只量\"做不做某件事\"。书里说，选择和谁交往，用它同样有效。和一个人来往，要花时间、体力、脑力，甚至金钱——那就照样问一句：这个人，真的值吗？","书里把人生大事浓缩成四个字：\"识人断物\"。做事要有判断标准，交朋友也要有。标准可以很严格，落到最后，其实只剩两个字——\"值吗？\""],"art":"data:image/svg+xml;base64,","caption":"一把尺子，两头都能量——人生大事，说到底是\"识人断物\""}],"quote":"\"今天我要做的这个事情，真的值我一生的万分之一吗？\"","quoteSrc":"—— 《专注的真相》：这是一道极其简单直接、却异常有效的是否问答题。到最后，落实成两个字而已——\"值吗？\"","reflect":[{"q":"回想昨天你花时间最多的三件事——如果每件都问一句\"它值我一生的万分之一吗\"，哪几件经得起问？","hint":"没有标准答案。有些事过不了关也没关系，关键是你开始\"掂量\"了。写在你自己的本子上。"},{"q":"这把尺子也能量人。你身边有没有一个人，是你愿意为他花时间、也确实\"值得\"的？","hint":"\"识人断物\"不是要你算计，而是把你最贵的注意力，留给真正值得的事和人。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一个三天小实验：每天挑一件你正打算花不少时间的事（刷视频、打游戏、约朋友、做一个项目都行），动手前先停三秒，问自己那句话——\"这值我一生的万分之一吗？\" 然后在本子上记下：通过 ✓ 还是没通过 ✗。三天后回看那张清单，你或许会发现，真正卡住你的，不是不努力，而是从没替自己掂量过分量。"},"09-master-or-servant":{"id":"09-master-or-servant","kicker":"成长读本 · 把时间当作朋友","title":"你不是大脑的奴隶","hook":"你大概有过这种时候：明明跟自己说\"就看五分钟\"，结果一个多小时过去了；明明想早点睡，手却一直在划手机。\n 那一刻，到底是\"你\"在做决定，还是你的大脑替你做了决定？\n 这一篇想讲的，是一件可能改变你一生的小事——你和你的大脑，谁是主，谁是仆。","sections":[{"h3":"1一件神奇的事：你能用大脑，控制大脑","paras":["书里说，人一生中\"最震撼的经历\"，是发现一个神奇的现象——我们竟然可以用自己的大脑，控制自己的大脑。","这有多特别？你可以拿锤子去砸钉子，却没法用同一个锤子去砸它自己。可大脑不一样：你能停下来，想一想\"我刚才那样想，对不对\"。这种\"把自己的思考当成思考对象\"的能力，有个名字，叫元认知。它正是人和动物最大的区别。"],"art":"data:image/svg+xml;base64,","caption":"\"我们甚至可以思考，我们的思考方式是否合理\"——这就是元认知（《把时间当作朋友》）"},{"h3":"2分清主仆：大脑是\"你的\"，但不是\"你\"","paras":["书里有一句话，值得你慢慢读三遍：\"你的大脑并不是你，你的大脑是（属于）'你的'大脑。\"","意思是：你用它思考，它好像也在指挥你的行动——但你不该隶属于它，应该是它隶属于你。\"跟着感觉走\"，就是无意识地被大脑牵着跑；停下来想一想再决定，就是你在有意识地控制大脑。区别只在这一念之间。"],"art":"data:image/svg+xml;base64,","caption":"\"运用心智获得解放\"——翻身做大脑的主人，而不是它的奴隶"},{"h3":"3最极端的证明：连最坏的处境也夺不走它","paras":["书里讲了一个人——奥地利的精神病学家维克多·弗兰克。他的父母、妻子、兄弟都死于纳粹之手，他自己被关进集中营，受尽折磨。可他在那里想明白了一件事：","人所拥有的一切都可以被剥夺，唯独一样不能——在任何境遇里，选择自己态度和生活方式的自由。于是身处牢笼，他仍在脑海里设想自己重获自由后站上讲台。能控制自己的大脑，就连最坏的处境也关不住你。"],"art":"data:image/svg+xml;base64,","caption":"\"唯独人性最后的自由——选择一己态度的自由，不能被剥夺。\"——弗兰克"},{"h3":"4好消息：这块\"主人\"的本领，可以越练越强","paras":["书里把一个人的心智，定义成他\"过往全部知识和经验的总和\"——也包括由此形成的思考方法和模式。心智不等于智商：很多智商正常的人，会做出\"聪明人办傻事\"的判断，正是因为心智还没被开启。","而心智这东西，\"上不封顶，下无保底\"。一旦开启，它会像滚雪球一样越长越快；但如果中途出错，也可能停滞甚至倒退。换句话说——你今天怎样对待自己的大脑，决定了它往哪个方向长。"],"art":"data:image/svg+xml;base64,","caption":"同一个起点，三种走向——选哪条，取决于你是不是大脑的主人（《把时间当作朋友》）"}],"quote":"\"不要再让自己'跟着感觉走'，成为大脑的奴隶，而是翻身做大脑的主人。\"","quoteSrc":"—— 《把时间当作朋友》第一章「醒悟」：这就是所谓的\"运用心智获得解放\"。","reflect":[{"q":"回想最近一次\"跟着感觉走\"、事后有点后悔的事。如果当时你\"停下来想三秒\"，可能会怎么选？","hint":"没有标准答案。重点不是责怪自己，而是看清——那一刻，是你在做主，还是大脑在做主。写在你自己的本子上。"},{"q":"弗兰克在最坏的处境里都没放弃\"选择态度的自由\"。在你自己不太顺的时候，你还能选择的那一点点东西，是什么？","hint":"哪怕只是\"我决定怎么看这件事\"，那也已经是你在当大脑的主人了。"}],"actionTitle":"🎯 行动卡 · 本周","action":"给自己做一个\"暂停三秒\"实验：这一周，每当你感到一股冲动——想刷手机、想放弃、想发火——先别动手，在心里默数三秒，问一句：\"现在是'我'要这么做，还是我的大脑想这么做？\"然后再决定。每天睡前，在本子上记一笔今天成功暂停了几次。一周后回看那串数字，你或许会发现：当主人，其实就是从这多出来的三秒开始的。"},"10-time-unmanageable":{"id":"10-time-unmanageable","kicker":"成长读本 · 把时间当作朋友","title":"时间，其实管不了","hook":"你大概有过这样一个下午：决心\"正式开始\"写作业，坐下没几分钟，先去倒了杯水，又顺手看了会儿手机，换了首歌，回了条消息……\n 等你一抬头看表，两个小时过去了，一页都没写完。\n 这一篇想讲一件听起来反常、却可能让你松一口气的事——时间根本没法管理；你真正能管的，只有自己。","sections":[{"h3":"1\"没时间了\"的恐慌，会让人既勤奋又懒惰","paras":["书的作者教过几万名学生，他发现绝大多数人身上都有一对矛盾：\"既勤奋又懒惰\"。一边周末早起挤公交去上课、恨不得废寝忘食；一边又满脑子找捷径，最好\"不费吹灰之力\"就把事办成。","他举了个真实的例子：有学生认真到要把一本范文集里的 185 篇全背下来，却来问他——\"考场上默写一篇，会不会被判雷同？\"如此用功，怎么会懒？根子在于一句反复闪现的话：\"没时间了。\"这种恐慌，逼出虚假的勤奋，也逼出投机的懒惰。"],"art":"data:image/svg+xml;base64,","caption":"\"既勤奋又懒惰\"——都来自对\"时间压力\"的恐慌（《把时间当作朋友》）"},{"h3":"2钥匙不在锁上：盯着\"时间管理\"没用","paras":["书里打了个比方：一扇门被锁住了，你想找钥匙——可钥匙一定不在锁孔里，否则门就不会是锁着的。\"没时间了\"的尴尬，就是那把锁；死盯着这把锁，打不开门。","很少有人注意到：\"时间管理\"其实是个虚假的概念。时间不服从任何人。你没法冲它喊\"慢一点\"，也没法叫它\"快一点\"，它只会用自己的速度自顾自地流逝，不受你影响。所以，从\"管理时间\"入手解决问题，注定徒劳——钥匙在别处。"],"art":"data:image/svg+xml;base64,","caption":"\"我们无法管理时间\"——它只自顾自地流逝（《把时间当作朋友》）"},{"h3":"3问题出在我们自己身上","paras":["你可能听过那个经典方法：把事情分成\"重要/不重要\"\"紧急/不紧急\"，先做\"又重要又紧急\"的。听上去很有道理，实际用起来却常常失灵。为什么？因为你往往没有足够的能力，去判断一件事到底重不重要、急不急。方法是对的，可操作的人是你。","于是结论变得很朴素：我们无法管理时间，真正能管理的，是我们自己。这话听着简单，接受起来却不容易——因为它常常和你过去\"想当然\"的观念相反，而人最难接受的，正是与已有观念相左的东西。"],"art":"data:image/svg+xml;base64,","caption":"\"我们真正能够管理的，是我们自己\"（《把时间当作朋友》）"},{"h3":"4唯一的解法，是相信积累","paras":["那\"管理自己\"具体管什么？书给出的答案只有四个字：一切都靠积累。你管不住流逝的时间，但你能决定今天往里面放进什么——多读的一页、多练的一次、多想清楚的一个问题，都会被时间替你存起来。","关键在那一句：\"深信积累的力量，时间就是你的朋友；否则，它就是你的敌人。\"同样的时间流过两个人，区别不在谁更会\"管时间\"，而在谁一直在往里存东西。把它当朋友，它就站在你这边。"],"art":"data:image/svg+xml;base64,","caption":"同样的时间，存与不存，几年后差距巨大（《把时间当作朋友》）"}],"quote":"\"我们无法管理时间。我们真正能够管理的，是我们自己。\"","quoteSrc":"—— 《把时间当作朋友》第〇章「困境」：深信积累的力量，时间就是你的朋友。","reflect":[{"q":"回想那个\"两小时没写完一页\"的下午。真正卡住你的，是\"时间不够\"，还是别的什么？","hint":"没有标准答案。试着把\"没时间了\"翻译成更具体的一句话——比如\"我一直在被打断\"，或\"我没真的开始\"。写在你自己的本子上。"},{"q":"如果时间管不了，那这一周你打算往里\"存\"进去的，是哪一件小事？","hint":"越小越好、越能每天重复越好。能被你重复存进去的，才会被时间替你放大。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一个\"估时实验\"：这一周，每开始一件事之前，先在本子上写下\"我猜它要花 ___ 分钟\"；做完，再记下\"实际用了 ___ 分钟\"。一周记 5 件就好。周末回看这两列数字，你或许会发现——自己习惯性地高估或低估。这不是为了责怪自己，而是因为\"管理自己\"的第一步，是先看清自己到底是怎样的。能预测自己，才谈得上安排自己。"},"11-accept-reality":{"id":"11-accept-reality","kicker":"成长读本 · 把时间当作朋友","title":"没有捷径，只有交换","hook":"你大概有过这样的开头：新学一样东西——吉他、编程、滑板、一门外语，\n 头几天看不到自己\"变厉害\"，就开始烦，开始上网找\"7 天速成\"\"一个月精通\"。\n 这一篇想讲一件你可能不爱听、却迟早受用的事——速成根本不存在；真正能用的，只有一个字：换。","sections":[{"h3":"1\"想马上看到结果\"，是写在天性里的","paras":["几乎人人都想速成，连老人家的劝告都先说\"戒躁\"——可说了千百年，我们还是急。书里点破了根子：人有一种\"希望欲望马上得到满足\"的天性。最好不劳而获；退一步，也要\"劳\"得尽量少、\"获\"得尽量多、最好马上拿到。","书里举了个例子：赌场里的老虎机最受\"赌鬼\"欢迎，不是因为更容易赢，而是拉一下手柄，5 秒之内就能知道结果。是输是赢都不重要，重要的是\"马上\"。减肥广告说\"当天见效\"、培训班叫\"一招制敌\"，全在喂你这条天性。看懂这一点，你才不会怪自己\"没耐心\"——这是出厂设置，但你可以校准它。"],"art":"data:image/svg+xml;base64,","caption":"\"马上出结果\"是天性的诱饵；真本事从来不在 5 秒里（《把时间当作朋友》）"},{"h3":"2有些阶段，谁都跨不过去","paras":["浮躁还有第二个根：很多人不懂\"有些阶段就是无法跨越\"。他们总不现实地盼着找到一个法子，\"啪\"一下就到终点。可书里举了个谁都驳不倒的例子——没有人能今天怀孕、明天生产。从受精到出生，大约 40 周，这个阶段无从跨越。再聪明、再有力气，一位母亲也得等这么久。","学东西也一样。你跳过的每一步，迟早要回来补；省下的时间是借来的，连本带利还。承认\"这一段就是要花时间\"，听上去泄气，其实是松绑——你不必再为\"怎么还没成\"而内耗。"],"art":"data:image/svg+xml;base64,","caption":"\"无论做什么都需要时间，而且可能需要很多时间\"（《把时间当作朋友》）"},{"h3":"3速成不行，那就\"换\"","paras":["速成不可能，那怎么办？书给的答案只有一个字：换。\"一分耕耘，一分收获\"，说到底也是这一个字。不成熟的人有个通病——整天想\"我要……\"，却没注意自己其实\"一无所有\"。每个人都从起点出发，最初都一无所有，然后用努力、用勤奋，去换能换到的东西。","积累多的人为什么稳？因为他的\"我要\"可以用\"我有\"来换；就算暂时不够，凭已有的努力和经验，假以时日也能换来，于是越换越多，形成良性循环。而积累少的人，\"我要\"的火越烧越旺，却没有东西可换，急也没用。差别不在谁更想要，在谁手里有可换的东西。"],"art":"data:image/svg+xml;base64,","caption":"\"给我什么我就用好什么，积累到一定程度再去换能换的东西\"（《把时间当作朋友》）"},{"h3":"4一张纸，就能让你脚踏实地","paras":["书里给了个特别朴素的工具：拿一张纸，从中间划开，左边写\"我有的\"，右边写\"我要的\"，逐条列出来。然后冷静地做两件事：先划掉那些现在的\"我有\"根本换不来的\"我要\"；再在剩下能换到的里面，圈出真正重要、不可或缺的那几个。","就算列到最后发现\"自己几乎什么都没有\"，也别灰心——对一个正常人来说，\"还有时间、还有精力、还有正常的智商\"，就已经够了。这张纸的魔力，是每次你冒出\"我要……\"，它都把你拽回来想一句\"那我有什么\"，瞬间脚踏实地。"],"art":"data:image/svg+xml;base64,","caption":"左栏盘点本钱，右栏划掉\"换不来的\"——剩下的，就是这周能开始换的（《把时间当作朋友》）"}],"quote":"\"告诉自己：我有不足，我需要时间，我没办法一蹴而就。\"","quoteSrc":"—— 《把时间当作朋友》第二章「现实」。时间是现实的人的朋友，是不现实的人的敌人。","reflect":[{"q":"最近有没有一件事，你因为\"没马上变厉害\"就想放弃？它真正需要的，会不会本来就是更长的时间？","hint":"没有标准答案。试着估一估：这件事，靠谱的人大概练了多久才像样？把这个数字写下来，再看自己练了几天。"},{"q":"如果只能用\"我现在已经有的东西\"去换，你最想换到的那一样，是什么？","hint":"越具体越好。\"我要变厉害\"换不动；\"我有每天 20 分钟，想换会弹一首完整的歌\"——这种就换得动。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一张\"我有 / 我要\"清单：拿张纸划成两半，左边尽量多地写下你现在已经拥有的（时间、工具、已会的本事、能帮你的人），右边写下你想要的。然后划掉右边那些\"现在的我有\"完全换不来的，给剩下的排个序。这周只挑最上面那一个，开始用左边的东西去换它——哪怕每天只换 15 分钟。一周后回看：你往里\"存\"进去的，时间都替你记着。"},"12-time-log":{"id":"12-time-log","kicker":"成长读本 · 把时间当作朋友","title":"你的时间，到底去哪了","hook":"想想昨天下午——它过去了，可你说得清它去哪了吗？\n \"好像也没干啥，一下午就没了。\"\n 这一篇想给你一个朴素到有点土的工具：一支笔、一个本子，把时间花在哪记下来。不是逼自己自律，而是先看清。看清了，你才管得动。","sections":[{"h3":"1管不了时间，但能\"看清\"它","paras":["上一篇说过：时间没法管理，能管理的只有你自己。可\"管理自己\"听着太大、太虚，从哪儿下手？书里给的第一步特别具体——先搞清楚自己的时间都花到哪里去了。","这和管钱是一个道理：理财的第一步，是弄清楚自己的钱都花在了什么地方；感知时间的第一步，也是弄清楚自己的时间都用来做了些什么。钱花没了你还有账单提醒，时间花没了却悄无声息——所以更需要你亲手把它记下来，它才\"看得见、摸得着\"。"],"art":"data:image/svg+xml;base64,","caption":"\"正如理财第一步是弄清钱花在哪，感知时间的第一步就是搞清时间用在了哪\"（《把时间当作朋友》）"},{"h3":"2有个人，这样记了一辈子","paras":["书里讲了一位苏联昆虫学家——柳比歇夫。他从 26 岁开始，给自己做一种\"事件—时间日志\"：每做完一件事，就在后面记下花了多少时间。比如：","这样的记录，他坚持了 56 年，一直到去世。靠着它，他清楚地知道自己每年、每月真正做了什么，留下了 70 多部学术著作。神奇的不是他多自律，而是这套方法朴素到——每天只花十来分钟就能记完。"],"art":"data:image/svg+xml;base64,","caption":"\"做这件事其实每天只需要花 10 分钟左右……并因此受益无穷\"（《把时间当作朋友》）"},{"h3":"3记\"花了多久\"，比记\"做了啥\"更值钱","paras":["很多人也写日记，但只记\"做了什么\"：今天背了单词、写了作业。这叫\"基于结果\"的记录。柳比歇夫高明在多写一样东西——每件事花了多少时间，这叫\"基于过程\"的记录。","差别看着小，用处大：当结果不好的时候，过程记录能帮你找到原因。\"这周英语没进步\"——翻开本子一看，原来一周只真正学了 40 分钟，时间全漏在了刷手机和发呆上。没有记录，你只会怪自己\"笨\"；有了记录，你看见的是\"时间漏在了哪\"，那是能改的。"],"art":"data:image/svg+xml;base64,","caption":"\"基于过程的记录……结果不好的时候更容易找到缘由\"（《把时间当作朋友》）"},{"h3":"4记着记着，你对时间的\"手感\"会变准","paras":["书里说，作者实践了不到两个星期，就体会到一个意外的好处：这种记录会让你对时间的感觉越来越精确。以前你估\"半小时能写完作业\"，结果两小时还没完，于是焦虑、自责。记得多了，你慢慢知道——同样一件事，你真实要花多久。","估得准，目标就定得现实；目标现实，就基本能达成；能达成，焦虑自然就少了。书里把这叫\"战胜焦虑\"。它不是靠打鸡血，而是靠你手里那本越来越准的\"时间账\"。"],"art":"data:image/svg+xml;base64,","caption":"\"它会使你对时间的感觉越来越精确\"——估得准，就能定出真正现实可行的目标（《把时间当作朋友》）"}],"quote":"\"感知时间的第一步，就是要搞清楚自己的时间都用来做了些什么。\"","quoteSrc":"—— 《把时间当作朋友》第三章「管理」。看不见的东西，没法管理；记下来，它才看得见。","reflect":[{"q":"凭印象，你觉得自己昨天在手机/游戏上花了多久？如果真去记一次，你猜真实数字会比印象大还是小？","hint":"没有标准答案。多数人会发现真实数字比印象大不少——这正是为什么\"记录\"比\"凭感觉\"靠谱。"},{"q":"有件你一直\"没进步\"的事，会不会其实是你真正投入的时间，比你以为的少得多？","hint":"先别怪自己。把这件事这周花的分钟数老老实实记下来，再下结论也不迟。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做三天\"事件—时间日志\"：找个小本子或手机备忘录，连续 3 天，每天睡前花 3 分钟，把当天做过的几件主要的事写下来，每件后面记上大概花了多久（像\"打游戏——70 分钟\"\"写作业——25 分钟\"）。第三天结束，回头看一眼：哪段时间，花得和你想的最不一样？不用评判，先看见就好。"},"13-self-learning":{"id":"13-self-learning","kicker":"成长读本 · 把时间当作朋友","title":"没人教你的时候，你还学得会吗","hook":"学校会一直给你\"标准答案\"，可总有一天，没有老师、没有教材，你要学的东西没人教你。\n 到那时，真正决定你能走多远的，不是你已经会了多少，而是一种更底层的能力：完全靠自己，把一样东西学会。\n 这一篇讲的就是它——自学能力。","sections":[{"h3":"1每学会一样，世界就多一扇门","paras":["书里说，学习是\"投资回报率最高的行为\"。为什么？因为知识的获取是不可逆的——在你知道它的那一瞬间，它就改变了一切，你再也回不到不知道的样子。","作者打了个比方：一个人若真的学会一门外语，他原本的世界就\"多了一扇门，跨过那个门槛，就是另一个世界\"。学会编程、学会演讲、学会一样新技能，都是这样——每掌握一项新技能，就像重生了一次。大多数人本可以\"一生过好多辈子\"，只是中途放弃了而已。"],"art":"data:image/svg+xml;base64,","caption":"\"任何知识的获取，都是不可逆的……他让自己拥有了另一个完全不同的世界\"（《把时间当作朋友》第四章）"},{"h3":"2自学能力，是四块基石叠起来的","paras":["自学不是一种神秘天赋，它是几种普通能力搭起来的。书里把它拆成四层，一层撑着上一层：","① 阅读理解是地基——不是\"识字\"，而是能读懂、能甄别信息真假。② 检索能力建立在熟练阅读之上——会用搜索引擎、查字典、翻资料，把\"其实唾手可得\"的有效信息找出来。③ 写作能力——能写出简洁、准确、说得清楚的文字，把学到的存下来、讲明白。④ 实践能力是最后一层，也是把前面三层\"变成真价值\"的关键：学了就去用。"],"art":"data:image/svg+xml;base64,","caption":"\"自学能力的基础是阅读理解能力……实践能力是自学能力最终转化为真正价值的根本\"（《把时间当作朋友》第四章）"},{"h3":"3进步不是斜坡，是台阶","paras":["有个\"不算太蠢但也足够蠢\"的幻想：只要努力，就会匀速地、一点一点地变好。书里说，事实不是这样——学习的进展和时间不是直线关系，而更像台阶。","很长一段时间你好像一点没进步（这叫\"平台期\"），然后某一刻突然窜上一级，接着又是长长的平台。所以当你\"学了好久却感觉原地踏步\"时，别急着断定自己不行——那很可能只是台阶的水平段，攒够了量，才会\"量变到质变\"。知道这一点，你就更熬得住那段看不见进步的日子。"],"art":"data:image/svg+xml;base64,","caption":"\"进展和时间的关系……更可能是阶梯状的：很长时间一点进展都没有，但从某一刻开始突飞猛进\"（《把时间当作朋友》第四章）"}],"quote":"\"知道自己需要的是什么之后，真正的学习才算开始。\"","quoteSrc":"—— 《把时间当作朋友》第四章「学习」。自学能力，就像恋人——你对它好，它才对你好。","reflect":[{"q":"上一次你\"完全靠自己\"学会一样东西，是什么时候、是什么？当时是哪一步让你最想放弃？","hint":"没有标准答案。回忆那一步，往往就是你自学能力里最薄的一块基石——下次有意识地补它。"},{"q":"遇到不会的，你的第一反应是\"问别人\"，还是\"先自己查\"？这两种习惯，五年后会把你带到很不一样的地方吗？","hint":"书里说，很多人英语没进步的本质原因只是懒——连字典都不愿意查。\"先自己查一圈\"是可以练出来的习惯。"}],"actionTitle":"🎯 行动卡 · 本周","action":"挑一件没人教过你的小事——魔方还原一层、一段吉他和弦、做一道没做过的菜、用某个软件的新功能，都行。规则只有一条：只靠免费的网上资料，自己把它学会，遇到卡点先自己查（搜索、看文档、翻评论区），实在不行再问人。完成后用三句话写下来：我卡在哪 / 我是怎么查出来的 / 下次我会先做什么。这三句，就是你这一周长出来的自学能力。"},"14-thinking-traps":{"id":"14-thinking-traps","kicker":"成长读本 · 把时间当作朋友","title":"三个思维陷阱，大多数人天天中招","hook":"广告里，很酷的人叼着烟；很酷的人开着那辆车；很酷的人用那个手机。看多了，你心里会悄悄冒出一句：我也想酷，是不是也该来一个？\n 先停一下。有心理学统计，超过 70% 的人分不清一句话和它\"反过来\"的说法——也就是说，大多数人每天都在被同一类思维错误牵着走，却毫不知情。\n 这一篇，教你认出三个最常见的思维陷阱，然后一眼识破它们。","sections":[{"h3":"1反过来，不一定成立","paras":["\"吸烟的人看起来很酷\"——就算这句是真的，它也绝不等于\"很酷的人都吸烟\"，更不等于\"你吸烟就会变酷\"。一句话成立，把它\"反过来\"说，不一定还成立。数学课上这叫原命题与逆命题：原命题为真，逆命题不一定为真。","这正是广告设计者最舍不得放弃的手段，因为它至少对 70% 的人有效。要破解它，练一个小动作：每听到一句结论，就在心里把它反过来念一遍，看看还站不站得住。"],"art":"data:image/svg+xml;base64,","caption":"\"反过来不一定成立。\"（《把时间当作朋友》第五章「思考」·逆命题）"},{"h3":"2一起出现，不等于谁造成谁","paras":["有人说：\"现在大家看屏幕越来越多，面对面聊天越来越少，所以是屏幕毁了我们的交流。\"这两件事确实一起在发生——但\"一起出现\"不等于\"一个造成了另一个\"。","书里给了一把尺子。看到\"因为 A，所以 B\"时，先问自己三句：A 真的是 B 的原因吗？就算是，A 是唯一的原因吗？就算是唯一的，A 是最重要的原因吗？（一个人回家不说话，也许根本不是因为看电视，而是那天丢了工作、心里堵得慌。）三句问下来，很多\"看似顺理成章\"的结论就露馅了。"],"art":"data:image/svg+xml;base64,","caption":"\"A 不一定是 B 的理由；不一定是唯一的理由；不一定是最重要的理由。\"（《把时间当作朋友》第五章·因果关系）"},{"h3":"3你越信它会发生，它就越可能发生","paras":["还有个更隐蔽的陷阱：有些事本来不一定发生，可只要很多人相信它会发生，它就真的发生了。一家好好的银行，只要传出\"它要倒了\"的谣言，大家慌着去取钱，它就真的被挤兑倒闭——这叫自证预言。","学英语也是这样。有人从小被反复告诉\"中国人学英语很难，十几年才背几千个单词\"，信了之后，就真的一辈子没学好。这不是笨，是那个念头应验了。反过来，不接这个\"诅咒\"的人，常常把外语学得很好。所以，格外小心那些\"你肯定不行\"的话——你信不信它，会真的改变结果。"],"art":"data:image/svg+xml;base64,","caption":"\"如果人们相信某件事情会发生……那么这件事情最终真的会发生。\"（罗伯特·莫顿\"自证预言\"，《把时间当作朋友》第五章）"}],"quote":"\"反过来，不一定成立。\"","quoteSrc":"—— 《把时间当作朋友》第五章「思考」。据统计，七成以上的人分不清一句话和它反过来的说法——认出这一点，你就已经不在那七成里了。","reflect":[{"q":"最近有没有一句广告词、或一句\"大家都这么说\"的话，让你差点信了？把它反过来念一遍，还站得住吗？","hint":"没有标准答案。广告最爱用\"反过来\"骗人——你多念一遍，就少上一次当。写在你自己的本子上。"},{"q":"有没有一句\"你肯定学不会 / 做不到\"的话，你曾经真的信了？如果当时你没信，结果会不会不一样？","hint":"没有标准答案。自证预言的可怕在于：信或不信，本身就会改变结果。你其实可以选择——不接那个\"诅咒\"。"}],"actionTitle":"🎯 行动卡 · 本周","action":"当一周的\"思维陷阱侦探\"。这周只要听到一句\"因为…所以…\"、一句广告口号、或一句\"你肯定不行\"，就把它记到本子上，然后用三把尺子量一量：① 反过来还成立吗？② 这真是唯一 / 最重要的原因吗？③ 如果我不信这句话，结果会不会不同？记满 5 条。一周下来你多半会发现——原来自己每天都差点被绕进去。"},"15-listening":{"id":"15-listening","kicker":"成长读本 · 把时间当作朋友","title":"会听的人，其实很少","hook":"同一个老师，同一堂课，讲给一整个班的人听。可下课后你会发现：真正听懂、抓住重点的，永远只有那么几个。\n 我们从小学\"说话\"、学\"阅读\"，却几乎没上过一节\"怎么听\"的课——好像\"听\"是天生就会的。\n 可事实是：一段交流成不成，往往不取决于说的人，而取决于听的人。这一篇，讲怎么把\"听\"练成一种真本事。","sections":[{"h3":"1你以为在听，其实大脑在偷偷溜号","paras":["人说话的速度，远远低于人思考的速度。别人一句话还没说完，你的脑子早就转完好几圈了——于是那些\"多出来\"的脑力没处放，就自动开始走神。","可怕的是它会\"上瘾\"：第一次溜号只有几分之一秒，回过神来发现好像没错过什么，大脑就\"证明\"了自己游刃有余，于是下一次溜得更久、更放心……直到真的错过了关键信息还不自知。更麻烦的是，说话的人为了讲清楚，总把最重要的结论留在后面。结果就是：说的人信息越来越重要，听的人接收得却越来越少、越来越碎。"],"art":"data:image/svg+xml;base64,","caption":"\"人类讲话的速度往往远低于思考的速度，所以我们在倾听的过程中常常会出现走神的现象。\"（《把时间当作朋友》第六章·交流）"},{"h3":"2最忌讳的一件事：没等人说完就反驳","paras":["\"质疑精神\"是好东西，但放错了地方就成了绊脚石。倾听时最该忍住的，就是过早质疑——话才听一半，就急着在心里（或嘴上）反对。","为什么？因为一个人刚开口时，论证是最不完整的，这时候你觉得\"他漏洞百出、不堪一击\"——这几乎一定是错觉。真正的证据、迂回的说理、意味深长的结论，都还在后面。更糟的是，一旦你进入\"反驳\"模式，就会像\"视而不见\"一样\"听而不闻\"，把后面真正有用的部分全挡在门外。接收，不等于接受：先让信息进来，不代表你要照单全收；但一上来就拒收，你连判断的机会都没有了。"],"art":"data:image/svg+xml;base64,","caption":"\"就算需要质疑，也一定要等到对方把话说完。\"（《把时间当作朋友》第六章·交流）"},{"h3":"3把多出来的脑力，用在\"回顾\"和\"预期\"上","paras":["既然思考比说话快、脑子一定有富余，那就别让它去走神，而是派它做两件事：回顾——他刚才到底讲了什么、要点之间是什么关系；预期——照这个逻辑，他下一句可能要讲什么。光是\"预期\"这一个动作，就会自动把你的注意力拉回来，还让你\"听到\"很多本来会漏掉的东西。","还有一把好用的尺子：把对方说的话分成两类。是事实，就想一想\"这是真的吗、可靠吗\"；是看法，就想一想\"他为什么会这么看、根源在哪\"。很多人逻辑混乱，不是因为逻辑难，而是嫌\"想\"太麻烦、干脆不想。最后，如果你是能被说话人看见的听众，给他一点回应——一个点头、一句\"那你看我这么理解对不对？\"——他会讲得更清楚，甚至自己就把疏漏补上了。"],"art":"data:image/svg+xml;base64,","caption":"\"在倾听的过程中，我们可以利用多余的脑力处理两个方向的信息：'回顾'与'预期'。\"（《把时间当作朋友》第六章·交流）"}],"quote":"\"交流的有效与否，往往更取决于听者而非说者。\"","quoteSrc":"—— 《把时间当作朋友》第六章「交流」。会不会听，几乎能决定一个人能走多远——因为绝大多数时候，你的成长都依赖听懂某些人的话。","reflect":[{"q":"回想上一次你和别人\"越聊越僵\"、最后差点吵起来——是对方没说清，还是你没等他说完、太早下了结论？","hint":"没有标准答案。书里说，很多认真的交谈最后变成争吵，被忽略的关键常常在听者一方：该确认时武断下定论，该回应时沉默。写在你自己的本子上。"},{"q":"你更像\"一听就信\"的人，还是\"一听就想反驳\"的人？这两种习惯，哪一种更容易让你停止进步？","hint":"没有标准答案。接收状态未必有害（除非全盘照收）；但排斥状态会让人永远进不来新东西——因为拒绝接收，就无从接受。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一周的\"忍住不打断\"实验。这周和别人（老师、家人、同学）认真说话时，给自己定一条铁规矩：不管多想反驳，都等对方把这段话完整说完，再开口。开口前先用一句确认：\"那你看我这么理解对不对——你的意思是……？\"每成功一次就记一笔，记满 7 次。一周下来留意两件事：你有没有发现\"听到最后，自己的疑问其实变了\"？对方是不是因为你在认真听，讲得越来越清楚？"},"16-compound-interest":{"id":"16-compound-interest","kicker":"成长读本 · 把时间当作朋友","title":"积累不是加法，是乘法","hook":"一个问题：你有 10 万元，年利率 10%，什么都不做，30 年后会变成多少？\n 多数人心里的答案接近 40 万——本金加上每年的利息，30 年嘛，10 万 × 10% × 30 ＝ 30 万利息，一共 40 万，听起来已经不少了。\n 可真实的答案是 174.5 万——超过本金的 17 倍。差出去的那 130 多万，就藏在两个字里：利滚利。这不只是钱的规律，也是习惯、技能、健康的规律。","sections":[{"h3":"1莎士比亚的算法，和夏洛克的算法","paras":["复利的公式并不复杂：S = P(1+i)ⁿ——P 是本金，i 是每期的利率，n 是期数，S 是最终的本利和。10 万本金、年息 10%、放 30 年，代入公式就是 174.5 万，而不是 40 万。","差别出在\"怎么算\"上。很多人默认用的是莎士比亚的算法：一年 365 天，每天进步一点点，最终收获就是简单地把 365 个\"一点点\"加起来。可现实运行的其实是夏洛克的算法——每天的进步不是加在原来的基础上，而是乘在原来的基础上，一年下来的结果接近 P(1+i)，是指数级增长，不是线性叠加。"],"art":"data:image/svg+xml;base64,","caption":"\"如若真的每天进步一点点，一年下来，收获最终很可能是 P(1+i)……这是夏洛克的算法——指数级增长。\"（《把时间当作朋友》第七章·应用）"},{"h3":"2复利不分好坏——它对坏习惯同样生效","paras":["\"习惯决定命运\"，说的正是复利。好习惯养成得越早，一生的收益就越大。但反过来同样成立：坏习惯也在收复利，而且利息高得像\"高利贷\"。","书里点名了一个最常见的例子——\"怕麻烦\"。学习效果差，往往是\"怕麻烦\"造成的疏漏；工作成绩差，往往是\"怕麻烦\"导致的偷懒。它的可怕之处在于：单看一次，利息并不高，\"不马上致命\"，就像一种慢性病，等到最终恶果一起爆发时，连本带利已经高到还不起。"],"art":"data:image/svg+xml;base64,","caption":"\"'怕麻烦'之类的坏习惯……'利息'并不高，甚至很低，只不过它'利滚利'……正因如此，坏习惯会在它的宿主身上'永垂不朽'。\"（《把时间当作朋友》第七章·应用）"},{"h3":"3连环境本身，也在替你计复利","paras":["生物心理学家罗森茨威格做过一个实验：把遗传素质差不多的老鼠分成三组——\"标准环境\"（普通笼子）、\"贫乏环境\"（单独隔离、几乎没有刺激）、\"丰富环境\"（一群老鼠住在有秋千、滑梯、木架梯的宽敞笼子里）。几个月后，\"丰富环境\"组最活跃，\"贫乏环境\"组最迟钝；解剖发现，两组老鼠在大脑皮层厚度、神经纤维数量等多项指标上都有明显差异。","每天多一点点刺激、多一点点被认真对待，单看一天几乎看不出任何区别——它也在利滚利，只不过利率、本金都藏在看不见的地方，几个月、几年后才会显出结果。"],"art":"data:image/svg+xml;base64,","caption":"罗森茨威格的老鼠实验：处在\"丰富环境\"中的老鼠几个月后最为活跃，\"贫乏环境\"组则明显迟钝（《把时间当作朋友》第七章·应用）"}],"quote":"\"相信积累的力量，本质上就是相信复利的力量。\"","quoteSrc":"—— 《把时间当作朋友》第七章「应用」。任何积累都需要时间，而且必然需要漫长的时间——这正是大多数人不肯积累、不愿积累的原因。","reflect":[{"q":"你现在有没有一个\"利息不高，但每天都在利滚利\"的好习惯？如果没有，你愿意从哪一件很小的事开始？","hint":"没有标准答案。书里说，好习惯养成得越早，一生的收益就越大——重点不是这件事听起来多厉害，而是它能不能每天做、能不能一直做。"},{"q":"有没有一件事，你一直因为\"怕麻烦\"而回避？它现在可能已经利滚利成什么样子了？","hint":"没有标准答案。\"怕麻烦\"最可怕的地方是\"不马上致命\"——正因为看不出眼前的坏处，才更容易被忽略，越拖利息越高。"}],"actionTitle":"🎯 行动卡 · 本周","action":"挑一件你想坚持的小事（比如每天读 10 页书、运动 15 分钟、背 5 个单词），连续做 21 天。每天在本子上打一个勾，再给自己\"今天做到了多少\"打个 1–5 分。21 天后回头翻一遍记录，看看这条曲线是不是也像复利一样——前面几乎看不出变化，后面开始悄悄加速。如果中间断了一天也没关系，接着记，复利要的是长期趋势，不是完美无缺。"},"17-read-the-manual":{"id":"17-read-the-manual","kicker":"成长读本 · 学习的真相","title":"学习，只不过是认真读说明书","hook":"两台电脑，同样的价钱、同样的配置、同样的性能。用上一段时间之后，它们的实际价值却天壤之别——一台还是普通电脑，另一台在主人手里好用得让旁人惊叹。\n 差别不在电脑上，在主人的一个习惯上：有没有认真阅读说明书。仅此而已。听起来小得不可思议？这一篇想让你看到：对成年人——以及快要成年的你——来说，所谓的学习，其实只不过是认真阅读说明书而已。","sections":[{"h3":"1说明书无所不在，只是几乎没人读","paras":["说明书不只是盒子里那本小册子。路标，就是行程说明书；地图和导航，是更复杂一点的行程说明书。可你观察一下就会发现：路标那么明显、那么清楚，甚至故意重复摆放，还是有很多人走错路；不少人看不懂\"上北下南\"的标准地图，开车只能用\"车头向上\"的傻瓜模式。","更严重的例子是药品说明书和医嘱。有研究调查表明，如果医嘱以文字形式展现，拒绝阅读的人会提高几乎 1/3——可医嘱只要略微复杂、超过三条，就只能用文字展现。于是医嘱被彻底执行的概率，远比医生们想象的低得多。这可是拿健康甚至生命在冒险，人们照样不读。","再看电脑：每个软件都自带帮助文档——结构清晰、说明清楚、可以全文检索、完全免费。可绝大多数人就是不看；与此同时，书店里大量热卖的电脑教程，本质上只是这些免费文档的改写。作者李笑来当年在新东方教书时用 Word 当板书工具，学生们总慨叹\"Word 原来可以这样用\"——他的回答是：一样的电脑、一样的软件，\"但我读说明书，大多数人不读啊\"。"],"art":"data:image/svg+xml;base64,","caption":"说明书无所不在——从路标到帮助文档。免费、清楚、随时可查，\"占比 99% 以上的人真的不看\"（《学习的真相》02·说明书）"},{"h3":"2任何知识，都只有三个构件","paras":["为什么\"读说明书\"就够了？因为任何一个知识点，归结到最后就三个构件：主体、机制、用法。新闻系学生学的 5W1H（何事、何人、何时、何地、何由、何法）归并一下也是它：what、who、when、where 都是不同性质的\"主体\"，剩下的就是 why（机制）和 how（用法）。","主体的发明和发现，通常是发明家、运气好的人做的事；机制，是科学家们才能彻底研究明白的事；而用法，是任何普通人都能在说明书的指导下彻底搞明白的事。买一台电视机回来，你不必是发明它的人，也不必彻底搞懂它的工作原理——在说明书的帮助下把功能用好，就够了。你在学校学的能量守恒定律也一样：不是你发现的，证明过程你也是\"挣扎着理解\"的，但教材（它就是物理知识的说明书）教会了你怎么用它——考试考的，恰恰就是用法。"],"art":"data:image/svg+xml;base64,","caption":"主体、机制、用法——普通人面对知识点的任务，就是搞明白\"用法\"（《学习的真相》02·说明书）"},{"h3":"3人类的特长：不懂原理，也能先用好","paras":["你可能会担心：\"不懂原理就去用，行吗？\"人类恰好特别擅长这件事。玻璃被人类使用了将近 4000 年，而人类彻底搞明白玻璃究竟是什么，恨不得已经到了 19 世纪。释迦牟尼在大约 2500 年前就用冥想主动锻炼、维护自己的大脑——他不知道大脑皮层是什么（那个年代不可能知道），但这并不妨碍他把\"用法\"用对；而脑科学家们彻底弄明白冥想的原理和好处，已经是 21 世纪的事了。","所以对普通人来讲，学，本质上更多是用。反过来，\"学而不用\"是绝大多数人终生的障碍——最明显的重灾区就是英语：初中三年、高中三年、本科四年，学了至少十年，却坚决不用，最终大面积失败，非常壮观。外语其实也有说明书：一本词典，加一本语法书。了解一下这两本\"说明书\"的结构，然后遇到问题就去查——不认识的词查词典，每个词都认识却还不懂就查语法书——慢慢查、经常查，就是学习本身。"],"art":"data:image/svg+xml;base64,","caption":"玻璃与冥想：人类格外擅长在不了解 what 和 why 的情况下，直接把 how 用得特别好（《学习的真相》02·说明书）"}],"quote":"\"学习啥难的呀，学习只不过是认真阅读说明书而已。\"","quoteSrc":"—— 《学习的真相》02「说明书」。这样的一句话，如果你真正理解了，会极大程度改变你未来的决策、未来的行动。","reflect":[{"q":"你天天在用的东西里（手机、某个 App、游戏、计算器、电子词典），有没有一个你从来没读过它的说明或帮助的？你猜它藏着多少你不知道的功能？","hint":"没有标准答案。书里说，帮助文档通常结构清晰、可以随时检索，而且完全免费——它们只是一直在等一个愿意读的人。"},{"q":"外语的说明书是\"一本词典 + 一本语法书\"。照这个思路，你正在学的另一样东西（游泳、编程、画画、下棋）的\"说明书\"是什么？","hint":"没有标准答案。任何知识都有主体、机制、用法三个构件——先去找讲\"用法\"的那部分，通常它就是这门手艺的说明书。"}],"actionTitle":"🎯 行动卡 · 本周","action":"挑一个你每天都在用的工具——手机相机、某个常用 App、电脑里的某个软件都行。花 20 分钟认真读一遍它的官方说明、帮助页或设置说明，找出 3 个你以前完全不知道的功能，记在本子上；再把其中最有用的 1 个，演示给家里人看。做完这件事，你大概率会听到那句熟悉的慨叹——\"原来还可以这样用？\""},"18-use-it-or-lose-it":{"id":"18-use-it-or-lose-it","kicker":"成长读本 · 学习的真相","title":"不练的手，不属于你的大脑","hook":"现在就试一个小实验：伸出右手，让无名指在前、中指在后交叉起来，再把食指和小指同时向两侧张开——这是 hip hop 爱好者的一个专有手势。除非你之前练过，你上来就是做不到，可能得用左手掰着摆才行。可只要来回练上几分钟，这只手忽然就会了。\n 刚才那几分钟里，你的大脑里到底发生了什么？答案会顺便解释两件事：为什么\"学这个有什么用\"多半是个错误的问题，以及为什么书里说——只要不练，你的手事实上就根本不属于你的大脑皮层。","sections":[{"h3":"1大脑是一张网：没有一种知识是孤立的","paras":["大脑里大约有 1000 亿个神经元，其中只有约 1/5（更准确地说约 19%）位于大脑皮层——用来构建文明和知识；另外约 4/5 负责协调整个身体。顺便澄清一个流传很广的说法：\"人脑只被开发了 10%，剩下 90% 都是潜力\"——科学家们很怀疑这个说法。它的来源是：大脑里除了神经元，还有约 10000 亿个神经胶质细胞，神经元数量只占全脑细胞的约 1/11。可胶质细胞不放电、不收发信号、不储存信息，它们只是固定神经元、为其绝缘、提供营养和氧分——并没有\"待开发的 90%\"。","真正重要的是另一件事：神经元之间不断形成连接，织成一张网络。哪怕两个神经元没有直接相连，它们也同处一网、必有间接联系——就像社交网络里的\"六度空间\"。成百上千甚至数万个神经元结成一个个功能模块，功能模块再组成一个去中心化的网络。于是有了一个结论：在大脑之中，没有任何信息、知识、能力是孤立的。也就是说——无论学什么都有用。","更进一步：你学得越多，已经学到的东西就越有用。这就是网络效应——网络中每个节点的价值，与节点数量的平方成正比。一个技能单独存在时价值是 1；当它和另外 4 个技能连成网络，它的价值可能就与 5² = 25 成正比了。"],"art":"data:image/svg+xml;base64,","caption":"节点的价值与网络节点数量的平方成正比——学得越多，已学到的越有用（《学习的真相》11·神经网络）"},{"h3":"2为什么有成就的人普遍多才多艺","paras":["有人调查过现代科学早期总计 120 名科学家，其中 61 名（一半以上）被认定是多才多艺的艺术家。你当然听说过爱因斯坦小提琴拉得很好，但你也许不知道他弹钢琴也是艺术家级别；哥白尼、伽利略、费曼都是这样。经济学家出身的托马斯·索因为自己的孩子六岁还不开口说话而去研究心理学，写出的论文《聪明的孩子晚说话》成了心理学领域被引用最多的论文之一；一位生理学教授因为度假考察鸟类的业余爱好，最后写出了《枪炮、病菌与钢铁》。","秘密不在\"天分\"，也不在\"更努力\"。任何技能都可以拆解成许多组成部分，交给大脑皮层上相应的功能模块处理；而那些看似毫不相关的知识与技能，拆到底层会有很多相似甚至相同的部分。通过素描练出来的灵活的手，写任何科目的作业都更快更好看；从小玩折纸的人，可能在数学或工程领域获得启发。功能模块可以被不同技能反复调用——所以结论是：学得越多，就学得越快、越好、越轻松。","反过来，\"少学而学精\"的策略其实很吃亏。有人研究过世界上最优秀的足球运动员，发现他们最初都不是从足球开始运动生涯的——游泳、田径、跳远、篮球，尝试过很多领域后才在足球上发力；而那些很早只钻研足球技术的运动员，反而缺了很多来自其他领域的必要技能。这种劣势有个名字，叫过早专业化。所以书里说：真的不能偏科——说实话，也没有什么\"偏科\"。"],"art":"data:image/svg+xml;base64,","caption":"功能模块被不同技能反复调用，而不是某个技能的专属零件（《学习的真相》11·神经网络）"},{"h3":"3内化、不用即弃，和\"方便陷阱\"","paras":["回到开头的手势。你练习时，大脑皮层里一些原本从没连接过的神经元，开始通过放电逐步连起来；一开始连接不通畅，所以你需要的只是大量重复，去强化、最终固化那些连接。用不了多久这只手就\"会了\"——而且练另一只手时，你会发现进程比上一次更快。这个能力叫内化：大脑皮层最强悍的本领。刚学开车时人人笨拙，重复次数够了之后，方向盘、油门、刹车就好像长在你身上，连后视镜都像多出来的三只眼睛；顶级台球运动员手里的球杆，可能比他们的手指更听话。大脑皮层压根不在乎一样东西\"生理上\"是不是你身体的一部分——只要反复练，它就把那当成自己的器官。","可怕的是，反过来也成立：不用即弃。你不练、不用的部分，你的大脑皮层就不认为那是自己的——哪怕它长在你身上。绝大多数人的绝大多数重要器官，都停留在出厂时\"够用即可\"的设置上，而\"够用即可\"总会在人生里不经意间变成一个又一个很深的陷阱。更进一步，如果你连\"思考\"都不用，你的大脑皮层就会在需要时按别人的想法运转——书里提醒：并不是你的大脑皮层认为\"女生数学差\"\"文科生不擅长逻辑\"，而是外部很多很多大脑皮层这么认为，然后把你\"内化\"了。所以，不会思考并不可怕，真正可怕的是不思考。","现代生活里还有一个方便陷阱：科技对我们太友好，以至于在悄悄剥夺练习的机会。拼写检查和自动纠正让人渐渐用纸笔写不出字；\"有自动翻译还学什么外语\"听起来有道理——但学外语本身就是健脑活动，就跟健身一样：脑子越练越好，不练就会慢慢变傻。仅仅有信息，并不等于有知识。"],"art":"data:image/svg+xml;base64,","caption":"练习=短时间内足量重复。连接由虚变实，工具变器官；反之，不用即弃（《学习的真相》12·用者无疆）"}],"quote":"\"用者无疆。要用你就好好用，不用等于放弃——不用即弃。\"","quoteSrc":"—— 《学习的真相》12「用者无疆」。大脑皮层就是这样：只要你用，它没有边界；只要你不用，哪怕长在你身上，它也不当回事儿。","reflect":[{"q":"书里说\"说实话也没有什么偏科\"——素描练出的手会让物理作业写得更快更好看。你自己有没有两样看起来毫无关系的爱好，其实在底层共用了同一批\"零件\"？","hint":"没有标准答案。试着把两样技能各拆成几个组成部分，再找找有没有重合的——手的灵活度、节奏感、空间感、表达，都是常见的共用模块。"},{"q":"拼写检查、自动翻译、计算器、导航……哪一个\"太方便的科技\"正在替你练本来该你自己练的东西？你舍得把那部分大脑皮层让出去吗？","hint":"没有标准答案。方便本身不是坏事——书里的提醒只是：别让为你服务的科技，暗中剥夺了你学习和锻炼的机会。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一次书里的手势实验：每天花 5 分钟，练\"无名指在前、中指在后交叉，食指小指同时张开合上\"这个手势。前 3 天练右手，后 2 天练左手。每天记一行：今天还需不需要另一只手辅助？书里预言第二只手会学得更快——用你自己的两只手验证它。练成那天，你亲眼见证了一批神经元连接从无到有、从虚到实。"},"19-memory-capacity":{"id":"19-memory-capacity","kicker":"成长读本 · 学习的真相","title":"过目不忘，是编出来的","hook":"电视剧和小说里，总有那种\"书页翻一眼就全背下来\"的天才，还有个专门的词：相机式记忆。你多半羡慕过——每个被\"记不住\"折磨过的人都羡慕过。但书里说得很干脆：这种能力是杜撰的。我们的大脑里压根没有内建一个像 Google 搜索引擎那样的装置，没有任何人的大脑能把一切输入原样永久保存、随取随用。\n 更有意思的是后半句：就算过目不忘真的存在，它也会让一个正常人变得更不聪明。想知道为什么，得先弄清记忆到底是怎么工作的。","sections":[{"h3":"1你的大脑是一台\"预测机\"","paras":["计算机的存储是仿生设计：速度快、容量小的内存，模仿的是人的短期记忆（也叫工作记忆，主要由海马体集中处理）；速度慢、容量大的硬盘，模仿的是长期记忆——它们分散保存在大脑皮层之中。","为什么记忆这么重要？因为大脑本质上是一台贝叶斯推理机——一个基于记忆的预测系统。每个新输入进来，大脑就调用相关的记忆模型去匹配，做出预测，再等待验证：出门看到天阴了，你顺手拿把伞，这就是一次\"输入—预测—验证\"。读书时也一样——读到\"她那美丽的……\"这五个字，你的大脑已经在飞快剔除选项：\"她\"排除了男性，接下来大概是眼睛、脸庞，多半不会是眼镜，更不会是帽子。你时时刻刻都在预测，而预测的全部依据，就是记忆。","反过来：如果你见过燕子低飞之后下雨，却记不住，那下次看到燕子低飞，你的大脑不会做出任何预测。记忆储备越低，可调用的模型就越少，预测能力就越差——书里说得不客气：预测能力过低，就是所谓的\"弱智\"。记忆甚至是意识和时间观念的基础：假如每晚把你的大脑\"重置\"回早上，白天发生的一切连接都被抹去，你连\"自己做过什么\"都无法承认。"],"art":"data:image/svg+xml;base64,","caption":"大脑=基于记忆的预测系统：不停剔除不可能的选项（《学习的真相》13·记忆容量）"},{"h3":"2记忆的核心不是信息，而是关联","paras":["大脑天然就是一个神经元网络，所以记忆也只能是一个网络：任何一个节点，若是和其他节点没有任何联系，它就不属于这个网络——没有被关联起来的信息，无法属于记忆。这就是为什么各种记忆法看起来\"有效\"：口诀\"一三五七八十腊，31 天永不差\"、谐音\"饿的话，每日熬一鹰\"（俄德法美日奥意英）、\"山巅一寺一壶酒\"（3.1415926）……它们的本质全都一样：原本的关联记不住，就人为造一条额外的关联。","但额外关联是有副作用的。上过国际学校的孩子用一首歌谣记十二个月份的中英对照，结果长大后每次要用某个月份，都恨不得把整首歌从头唱一遍才反应过来——典型的\"不必要的关联降低工作效率\"。那些记忆奇人也一样：有位乌克兰人能在两分钟内记住 5100 个数字、背出圆周率 100 万位，打破了此前 83431 位的世界纪录——用的依然是关联记忆术，不是什么相机式记忆。而你可以观察一个事实：我们知道的任何记忆大师，都不是顶尖的科学家或思想家。","书里有个很好的类比：科学由事实构成，正如房子由砖头砌成；但一堆砖头放在那里，不会自动成为房子。把\"科学\"换成\"知识\"、\"事实\"换成\"信息\"也一样成立——仅仅往脑子里塞信息，不会让你更聪明。恰恰相反：无意义的信息和没必要的关联越多，大脑在其中寻找有意义连接的难度，会成几何级数地提高。"],"art":"data:image/svg+xml;base64,","caption":"房子由砖头砌成，但一堆砖头不会自动成为房子（《学习的真相》13·记忆容量）"},{"h3":"3两个朴素得让人失望的方法","paras":["方法一：短时间内足量重复。书里的结论出人意料：到最后，最佳的记忆法真的就只有\"死记硬背\"——换个不容易误解的说法，就是短时间内重复足够多遍，并且尽量不建立不必要的关联。我们成长过程中做过的最正确的记忆经历就是背乘法表：没有借用任何记忆法，好处是大脑皮层上从未为它建立过任何多余的关联。（顺带一提：英美国家的人上学时没背过乘法表——用英文朗读它实在太费劲了。）","方法二：不断扩大知识量。这才是最重要的提高记忆能力的手段，朴素到几乎没人愿意信。原理还是网络：知识网络越大、节点越多，一个新节点进来时，能和它产生关联的\"抓手\"就越多，它就能更快更好地接进网络里。所以记忆力的运行机制和学习机制一模一样——你记得越多，就记得越快、越好、越容易。","这不是鸡汤，有测算数据：一个识字的人，记忆力（包括记忆容量、回忆的准确度和速度）比不识字的人高出至少一倍；多语使用者平均比单语使用者再高出约 1/5；于是多语使用者比不识字的人记忆力高出三倍以上。从这个角度看，\"学习让人变聪明\"不是空话，只能是事实——聪明，几乎全部靠后天积累。而用正确朴素的方法提高记忆容量，甚至是建立长期观念的前提。"],"art":"data:image/svg+xml;base64,","caption":"知识量越大，节点越多，新东西越容易\"挂\"上去（《学习的真相》13·记忆容量）"}],"quote":"\"记忆的核心并不是信息本身，而是信息之间的关联。\"","quoteSrc":"—— 《学习的真相》13「记忆容量」。同一章还有后半句：没有被关联起来的信息，无法属于记忆。","reflect":[{"q":"想一个你怎么都记不住的东西——某个单词、公式或年代。它是不是一块\"孤零零的砖头\"？试着给它找两个抓手：它像什么？和你已经知道的什么有关？","hint":"没有标准答案，写在你自己的本子上。抓手可以很朴素：在哪儿见过类似的、能不能用它造个句、它和哪门课的哪个知识点挨着。"},{"q":"你用过哪些口诀、谐音记忆法？有没有像\"月份歌谣\"那样，每次都得从头唱一遍才想起来的时刻？考完试之后，那些口诀还剩下什么？","hint":"没有标准答案。书里也承认记忆术对付考试有点用——它只是提醒你：额外关联是有代价的，别把记忆术当成记忆力本身。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一个抓手实验：挑出本周必须记住的 5 个新知识点，分成两组。前 3 个，每个写下 2 条它和你已知知识的关联（它像什么？在哪儿见过类似的？）；后 2 个，只用\"短时间内足量重复\"——念 3 遍，不加任何花哨口诀。周末合上本子自测：两组各记住了几个？哪组回忆得更快？把结论记成一行字。你会亲手测出自己大脑的记忆机制。"},"20-model-matching":{"id":"20-model-matching","kicker":"成长读本 · 学习的真相","title":"你看到的，是大脑猜出来的","hook":"1976 年，太空船维京一号从火星传回一张照片，无数人在一块岩石上看到了一张巨大的人脸；1954 年版的加拿大纸币上，人们在女王的头发里认出一张\"魔鬼面庞\"；2022 年尼康摄影竞赛里一张蚂蚁头部的正面特写获了奖，很多人看完直呼不适——因为它也\"长着\"一张魔鬼的脸。\n 火星上当然没有脸，头发就是头发，蚂蚁只是蚂蚁。问题来了：你的大脑为什么非要看见一张脸？答案会顺便解释：学习到底是怎么一回事。","sections":[{"h3":"1看，从来不是照相，是猜","paras":["心理学里有个专门的词，中文叫空想性错觉：大脑给一幅画面、一段声音强行赋予意义，而那个意义只是巧合——中国人叫\"无中生有\"。它在识别人脸时最常见，因为人一出生，脑子里就自带一个\"人脸模型\"：对刚出生的婴儿来说，判断一个会动的东西是不是人，主要就看它有没有脸。","这暴露了大脑的工作方式：一切识别，都是模型识别。模型是对事物若干主要特征的抽象组合。我们认东西时，大脑并不逐个细节对照，而是只提取少量重要特征，然后调用记忆里的模型去做预测——而且不求精确，大概对得上就开始猜，因为后面本来还有一个\"验证或排除\"的环节。我们之所以能在浓烟和岩石里\"看到\"脸，是因为人脸模型被调用的次数实在太多、太熟悉了，大脑总是先用最熟悉的模型去猜。书里还有个佐证：越迷信的人，越能快速认出\"魔鬼面庞\"——不是他们眼神好，是那个模型对他们来说更熟。","\"手里拿着锤子的人，看什么都像钉子\"，就是这个机制的经典案例：锤子在手，钉子模型就成了脑子里最重要的模型，看什么都先跟它配对。于是有了一个值得抄下来的结论：任何预测的依据，都来自自己最熟悉的领域。所以独立思考的起点，不是\"相信直觉\"，而是知道直觉只是一次待验证的猜测：验证失败就换模型、改模型；所有模型都不管用，就得建新模型——这个过程，就是独立思考的全过程。"],"art":"data:image/svg+xml;base64,","caption":"大脑的工作过程：基于最熟悉的模型做近似预测，再验证或纠正（《学习的真相》14·模型匹配）"},{"h3":"2\"桌子\"居然比\"圆\"难","paras":["直觉上，看得见摸得着的东西简单，抽象的东西难。书里的结论正好相反：我们给具象事物建的模型，其实更复杂、更含混；给抽象事物建的模型，反而更简单、更准确。","试试描述\"什么是桌子\"：平面要够大——多大算够大？说不清，太小就成了放花盆的架子。要够高——离地两米像亭子，40 厘米又成了茶几，界限在哪也说不清。平面得大致水平；有平面的柜子、台子又不算桌子；腿嘛，一条两条三条四条都见过，桌布垂下来看不见腿照样一眼认出；双层电脑桌有两个平面，也难不倒你。书里描述了六个方面，每一方面都含混不清——可你识别桌子只需要一瞬间。这也解释了为什么人工智能科学家想写出\"在图片里认出猫\"的算法竟那么难。","再看\"圆\"：从中心点到周边任何一点的距离完全相等的图形。一句话，每个字都毫无歧义。抽象模型必须简单、准确、无歧义，否则就没法被拿来继续搭建和组合。而我们在学校里学的语文、外语、数学、物理、化学，核心全是抽象概念——凡是真正重要的，几乎都看不见摸不着，全靠后天习得。所以书里说：大脑从一开始就是抽象机器，更擅长处理抽象事物。顺便撂下一句硬话：所谓\"女生天生不擅长数学、抽象能力弱\"，绝对是胡说八道——抽象能力不可能分性别，除非用的不是人脑。也因此值得真心崇尚科学：科学本质上就是对整个世界无歧义的、既简单又准确的抽象——基于它做预测更准，验证和试错的成本更低，有时几近于零。"],"art":"data:image/svg+xml;base64,","caption":"与直觉相反：具象模型含混复杂，抽象模型简单准确（《学习的真相》14·模型匹配）"},{"h3":"3学习 = 习得、应用、改良、构建模型","paras":["既然大脑皮层上一切都是模型，那么一个人的\"操作系统\"就由两个要素构成：模型，以及模型之间的关联——两者都要清晰、准确、必要。于是一切抽象知识的学习，最终无非是习得、应用、改良、构建模型的过程。连\"学习\"这个模型本身，都是被一代代人改良出来的：2500 年前，孔子说\"学而时习之\"——他的学习模型有两个零件：学 + 习；1000 年前，宋代的杨时在《论学篇》里补上了\"行\"；400 年前，清代的颜元说\"学而必习，习又必行\"。而书的作者认为践行不该在学习之外，还把\"行\"进一步拆成两半，得到四个零件：求学、练习、应用、创造——学、练、用、造。","这个模型好在哪？它说清了卡住时该去哪一格。作者自己举例：他是东北人，日常说话把\"取\"读成\"糗\"、说\"贼\"、说\"磕碜\"，够用，就一直用；直到要去新东方面对天南海北的学生讲课，\"应用\"这一格不够用了——只好回去重练普通话；等到要讲自己写的课，\"创造\"又逼他去学逻辑、研究方法、发声技巧，甚至回头重练记忆力和断句。学习就是这样循环往复，而创造是其中最能触发主动的一格——我们夸一个人\"自驱力强\"，其实只是在说他更主动，而呵护创造的欲望，就是变主动的办法。创造还必然需要组合技能：书里说见过无数优秀教师自己开学校却失败——教学再杰出，缺了销售、组织、协调、抗压，创造就是不成立。所以，只有创造能最大限度地反复触发学习，也只有创造才是学习效果的最终检验标准。","最后，怎么判断你建的模型好不好？就两个字：必要。不必要的零件直接删掉；若干零件拼成新模型时做到\"无需增减\"——多一个是多余，少一个不完整。书里的示范：知识的结构原本用 5W1H 六个零件描述，后来发现 who、when、where 都只是不同的 what，精简成三个——主体（what）、机制（why）、用法（how）。这就是一次漂亮的模型改良。"],"art":"data:image/svg+xml;base64,","caption":"\"学习\"这个模型本身，就是被一路改良出来的（《学习的真相》15·改良构建）"}],"quote":"\"基于最熟悉、最常用的抽象模型，做出近似的、有待验证或纠正的预测。\"","quoteSrc":"—— 《学习的真相》14「模型匹配」对大脑工作过程的总结。书里说：深入理解这句话，能在极大程度上提高独立思考能力。","reflect":[{"q":"\"手里拿着锤子的人，看什么都像钉子。\"——你手里有没有一把自己的\"锤子\"？回想最近一次你\"一眼就认定\"的判断（这人讨厌我 / 这门课没用 / 我肯定不行），它用的是哪个最熟悉的旧模型？后来验证过吗？","hint":"没有标准答案，写在你自己的本子上。提醒：瞬间得到的结论只是近似、粗略的猜测，并不值得直接信赖——验证失败也不丢人，那只是完成了一次试错。"},{"q":"孔子的\"学＋习\"过了两千多年才被补上\"行\"和\"造\"。想一样你正在学的东西（英语、数学、编程、乐器……），你现在停在哪一格：学过？练过？用过？有没有用它创造过什么——哪怕很小的东西？","hint":"没有标准答案。如果一直停在\"学\"和\"练\"，可以想想能不能给它找一个真实的用处；如果已经在\"用\"，试试造一个小东西——创造是最能把人变主动的一格。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一个\"猜—验\"实验：连续 5 天，每天记下 1 个你大脑瞬间给出的判断——\"这道题很难\"\"他生气了\"\"这本书无聊\"，一行就够。当天想办法验证：题目真做不出来吗？他真在生气吗？周末盘点：5 条里猜中几条？给猜错的每一条补一行——当时用的是哪个\"最熟悉的模型\"？该改良它，还是该换一个？你会亲眼看到自己的大脑是怎么\"猜\"的。"},"21-minimal-knowledge":{"id":"21-minimal-knowledge","kicker":"成长读本 · 学习的真相","title":"入门需要的，比你想的少","hook":"很多人一听\"五线谱\"三个字就摇头：那得学多久啊。可是识谱的入场券其实只有一句话——\"中间那根线是西\"：哆来咪发嗦啦西，往上接着数，往下倒着数。知道这一句，你就可以开始认谱了。\n 几乎每一样你想学的东西，都有这么一张短得惊人的\"入场券\"。真正的问题是：你有多少想学的事，卡在\"等我先学完、先准备好\"上，一直没有开始？","sections":[{"h3":"1MAKE：那张短清单","paras":["《学习的真相》给这个东西起了名字，还杜撰了一个英文缩写：MAKE，Minimal Actionable Knowledge and Experience——\"最少的可执行的知识和经验\"。意思是：任何领域都能提炼出一小把知识，掌握了它，你就可以马上开始用。","书里一口气给了好几张清单。学英语的最少必要知识只有三件：学会音标、学会查词典、有一本语法书——遇到不认识的词查词典，词都认识却读不懂就查语法书，今天还可以加上搜索引擎，然后就可以直接去\"用\"英语了（英语最大的用处本来就是阅读）。弹奏乐器：标准音高、能够识谱、节奏感、基本指法，四样在手就可以开始弹。文字创作只有两条：足够的感知，加上足够的识字数量——自然语言本来就是用来记录和表达感知的。绘画也是两条：眼手协调训练和几何构图训练——天下所有图形都以几何形状为基础，连直线都是曲度为零的曲线。","最让家长意外的是这张：应付学校考试的最少必要知识，第一是足够的写字速度，第二是足够的理解速度。写字太慢是最大的罪魁祸首——课堂上注意力都花在写字上，听到的就少，遗漏的就多。而提高理解速度只有一个朴素的办法：无限度提高阅读量，尤其是数学、物理这类\"人工语言\"的阅读量——读再多小说帮不上，快速阅读培训更是百害而无一利，因为输入再快，处理速度跟不上都没用。"],"art":"data:image/svg+xml;base64,","caption":"每张清单都短得惊人——掌握它，就可以马上开始\"用\"（《学习的真相》18·最少必要）"},{"h3":"2顺序反过来，才最划算","paras":["为什么要这么急着\"开始用\"？因为学习一共四个模块：学、练、用、造——求学、练习、应用、创造。书里的标准很硬：延伸到\"用\"才算及格，延伸到\"造\"才有真正的意义。学校教育普遍失败，恰恰是因为学生感觉不到刚需、灌输消灭了主动、关键点上从没做到短时间内足量重复，最后考试竟成了学和练的唯一用处——你就是这样把英语学废的。可考试顶多算\"练\"，它根本不是\"用\"。","主动也不是天上掉下来的。人脑天生为生存设计、天然短视，所以学习能力对大多数人来说是\"出道即巅峰\"，不加干涉就一路下滑。主动必须靠干涉和挣扎才能重新获得。那么问题来了：学练用造四个模块，主动最先加在哪一格最划算？","答案有点反直觉：从后往前。只要你把主动强加到\"造\"上——既然已经开始创造，应用就只能主动，练习也只能主动，连求学都自动变主动了。反过来从前往后走，每一格都得重新使一次劲：主动学不一定引发主动练，主动练不一定引发主动用。这就像下棋：双方棋子相同、规则相同，马都走日、象都走田，最后却有输赢——决定输赢的是顺序。所谓有策略，说穿了就六个字：知轻重，论先后。所以任何领域的学习，都要尽快走到\"用\"和\"造\"。"],"art":"data:image/svg+xml;base64,","caption":"顺序决定输赢：尽快走到\"用\"和\"造\"（《学习的真相》18·最少必要）"},{"h3":"3一条金线：最少必要经验","paras":["先泼一瓢冷水：清单虽短，简单并不见得容易。一切所谓的最少必要知识，就是人们常说的\"基础\"；而任何基础，都需要短时间内足量重复才能打牢——耗时费力，这是不可否认也无法更改的事实。音标要一个个啃，指法要一遍遍练，短清单只是让你不再绕路，不是让你不用走路。","MAKE 的后半截是\"经验\"。书里说，人生最重要的最少必要经验只有一条：你至少有过一次，至少在一个领域，通过逼迫（无论来自外部还是内部），做到短时间内足量重复，最终真正打下了一个扎实的基础。这是学渣和学霸之间的一条金线：从未有过这种经验的人，啥啥都基础差、都不够用，永远走不到\"用\"和\"造\"；而只要有过一次，它就会根植在大脑里，学任何新东西时被反复调用、反复验证、越用越强。作者自己的那一次，是少年时在少年宫学编程语言 BASIC——此后不管学什么，他都知道\"我能的，只不过需要花时间而已\"，连错误都成了奖励。","达尔文说过：除了傻子，人在智力上差别并不大，不同的只是热情和努力。马斯克说：我为了实现目标学会了一切需要学的东西，我认为大多数人都能做到，只是他们往往自我设限——人们的能力比他们想象的要强。书里提醒：千万别把这当鸡汤，这只不过是事实——能这么说的人，都是因为有最少必要经验垫底。所以一个优秀的教练，最大的任务就是两件事：甄别这个领域的最少必要知识；如果学生还没有最少必要经验，就用当前的任务帮他打造一次。"],"art":"data:image/svg+xml;base64,","caption":"学渣和学霸之间的金线，不是天赋，是一次经验（《学习的真相》18·最少必要）"}],"quote":"\"简单并不见得容易。\"","quoteSrc":"—— 《学习的真相》18「最少必要」。清单很短，但清单上的每一项都要短时间内足量重复才能打牢——短清单让你不绕路，不是让你不走路。","reflect":[{"q":"你有没有一件\"一直想学、但还没开始\"的事——滑板、吉他、编程、画画？试着替它列一张最少必要知识清单，很可能不超过三条。是哪三条？又是什么让你一直觉得\"还不能开始\"？","hint":"没有标准答案，写在你自己的本子上。提示：如果清单列出来发现只有两三条，那\"没准备好\"多半不是知识问题，而是没想过自己可以直接去\"用\"。"},{"q":"回想你学得最扎实的一样本领——骑车、游泳、口算、一款玩得很好的游戏。它是不是也有过一段\"短时间内足量重复\"的日子？那段经历就是你的\"最少必要经验\"——下次学新东西卡住时，你能把它调出来对自己说什么？","hint":"没有标准答案。作者的那一次是少年宫的 BASIC，之后一生反复调用。你的那一次同样算数——它证明的不是你会骑车，而是\"我能打下基础\"。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一次\"最短入场券\"实验：挑一样你想学但一直没开始的东西，第一天，只做一件事——写下它的最少必要知识，不超过 3 条（查资料、问会的人都行）。第二、三天，只学这 3 条。第四天起，马上去\"用\"：做出一个最小的真东西——弹出一小段曲子、写一段能跑的代码、画一张完整的小画。周末记两个数：从\"开始学\"到\"第一次用\"隔了几天？和你原来以为需要的时间差多少？"},"22-habit-is-process":{"id":"22-habit-is-process","kicker":"成长读本 · 学习的真相","title":"复杂的本事，拆开都是流程","hook":"姚明每次罚球前，都会做一套一模一样的动作：先运球五次，然后略微下蹲、把球举到和头一样高、停顿一下，再投出去。顺序从不改变。就靠这套固定动作，他在 486 场 NBA 里罚球命中率高达 83.3%；而同样位置的奥尼尔，只有 52.7%。\n 一个\"固定的顺序\"，凭什么差出这么多？因为你以为的\"本事\"，底层其实是一段流程——而流程，是可以拆开、看懂、重写的。","sections":[{"h3":"1习惯，就是你最常走的那条路","paras":["《学习的真相》把话说得很硬：所谓的习惯，只不过是神经元之间——因为最直接、最通畅，所以最常用的那个连接。大脑这张网按\"节能\"办事，传信号时总优先选最好走的那条路；走得越多，那条路就越通畅，于是越走越自动。这就是习惯。","那复杂的本事呢？也一样。1966 年有一篇被称为\"结构化程序定理\"的著名论文说：天下一切任务的执行流程，都只由三个模块拼成——顺序、循环、分支。最简单的习惯，不过是\"先做这个、再做那个\"的顺序连接，三块里最基础的一块。加上\"重复做\"就是循环，加上\"看情况决定做哪个\"就是分支。姚明那套罚球动作，就是一段被练到自动的\"顺序\"。"],"art":"data:image/svg+xml;base64,","caption":"顺序 · 循环 · 分支——本事拆到底，都是这三块（《学习的真相》19·流程而已）"},{"h3":"2为什么\"先做难的\"是更好的顺序","paras":["既然习惯是可以设计的顺序，那就有好坏之分。做作业、做练习，先做简单的还是先做困难的？书里给的答案是：先做困难的；卡住了，就转去做几道简单的；然后再回来继续攻那道难题。这不是玄学，背后有脑科学。","人思考有两种模式。专注模式（focus mode）像运动的物体，有惯性——你想让它停，它不会立刻停。所以当你把脑力从难题上暂时移开、去做简单题时，刚才那股专注的劲儿有一部分不会熄火，而是转入游离模式（diffuse mode），在相关的念头之间\"随机漫步\"，常常一不留神就撞见了最恰当的思路。阿基米德在浴缸里喊出 Eureka、牛顿在树下看苹果落地——灵光乍现之前，他们的大脑都在游离模式里。于是你回头再看那道卡住的难题，答案常常已经\"意外地\"冒出来了。先难后易还有个附带好处：像跑累了放慢速度接着跑、而不是干脆停下，它能练大你脑力的耐力。"],"art":"data:image/svg+xml;base64,","caption":"先难后易，不是硬撑，是让专注的余力在后台替你工作（《学习的真相》19·流程而已）"},{"h3":"3坏习惯删不掉——只能盖一条更宽的新路","paras":["这里有个反常识、但很重要的事实：一个已经养成的习惯，其实无法\"戒除\"。大脑不会、也不懂得删除那些已经固化的神经元连接。这条路一旦被走通、走宽，它就一直在那儿。所以\"删除坏习惯\"这个任务，严格讲根本不成立。","那怎么办？你能做的是另一件事：用刻意的重复，建立一条更直接、更通畅的新连接，让它去打败旧的那条。这也是为什么街上流行的\"21 天养成一个习惯\"多少有点一厢情愿——旧路早已很宽，新路要和它抢信号，谈何容易。除了\"短时间内足量重复\"，书里还给了三个帮新路变宽的基础动作：复习（每隔一段时间重做一次）、复用（把同一个好习惯用到不止一个领域，比如\"先难后易\"用到写作业、也用到练琴）、检查（定期回头看看自己复习、复用得怎么样；有外界监督可用，要感激地采纳）。再进一步：知道\"在什么情况下该启动哪个习惯\"，那就是加上了\"分支\"——书里叫它智能习惯。","把这一切连起来，作者给了一个让人有点震动的结论：所谓性格的好坏、甚至人品的高低，其实只不过是流程管理能力的差异而已。人们把体贴的人叫\"暖男\"，好像那是可遇不可求的天赋；可换个角度看，那只是这个人懂得建立流程、优化流程、并且知道在什么时候启动什么流程。这话反过来听，是好消息：人品可以打造，性格可以优化，情绪可以控制——一切又回到了你自己的掌控里。只是有两个提醒别忘：好习惯越早养成越好，而且它的养成或多或少总需要一点强制的辅助。"],"art":"data:image/svg+xml;base64,","caption":"改习惯不是\"删除\"，是\"盖一条更宽的新路\"去竞争（《学习的真相》19·流程而已）"}],"quote":"\"所谓性格的好坏，甚至人品的高低，其实只不过是流程管理能力的差异而已。\"","quoteSrc":"—— 《学习的真相》19「流程而已」。既然习惯只是流程，那人品就可以打造、性格就可以优化——一切回到你自己的掌控里。","reflect":[{"q":"挑一件你\"总是做得很好\"的事——某个游戏的开局、某道你很稳的题型、上台前的准备。它是不是也藏着一套你几乎不用想的固定顺序？如果把这套顺序写下来，你会发现哪几步？","hint":"没有标准答案，写在你自己的本子上。提示：能写出来的顺序，就能有意识地搬到别的事情上——这叫\"复用\"。"},{"q":"再挑一个你想改掉的坏习惯。既然它删不掉，只能被一条\"更好走的新路\"替代——那条新路具体是什么动作？什么信号出现时你就启动它（这就是给它加上\"分支\"）？","hint":"没有标准答案。比如\"一拿起手机想刷视频，就先把它放到另一个房间\"——信号是\"想刷\"，新动作是\"放远\"。重复到不用想，它就赢了。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一次\"姚明式启动流程\"实验：挑一件你每天都得做、却总要磨蹭半天才开始的事（写作业、练琴、跑步都行）。给它设计一套固定的 3 步启动动作，就像姚明罚球前那三下——比如\"清空桌面 → 只打开这一样 → 定 25 分钟计时\"。接下来连续 5 天，每次都用一模一样的顺序启动，一步都不改。每天记一个数：从\"决定开始\"到\"真正动手\"，中间犹豫了几分钟？看看这个数字，是不是一天比一天短。"},"23-plan-review":{"id":"23-plan-review","kicker":"成长读本 · 学习的真相","title":"计划，只需要计划复习","hook":"每个学期一开学，学校都会发一张课程表——精确到每个时间点、写满了每门课的名字。它是全班最正式的一份\"学习计划\"。可你有没有发现：计划明明百分百完成了，成效却常常很差。\n 于是很多人得出结论：\"计划赶不上变化，干脆别做了。\"但真相是另一句：不是计划没用，是你把计划做在了错的地方。","sections":[{"h3":"1学习几乎没有意外，值得计划","paras":["计划为什么总失败？根本原因是不确定性——出行的人越多、时间拉得越长，潜伏的意外就越多。可《学习的真相》点出一件容易被忽略的事：学习这件事，几乎没有不确定性。什么都值得学、学什么都有用、学什么都要花时间力气——完全没有意外。所以，学习恰恰是少数真正\"值得计划\"的事。","但\"值得计划\"不等于\"每一步都要计划\"。一天里，预习、认真听讲、复习——只有一个环节是面向未来的，需要提前安排；其余的按部就班就好。作者把话说得很干脆：仅仅拿出纸笔、按时间大致罗列一串学习任务，从来就不是有效的学习计划。课程表就是这种\"只列标题\"的典型，它的失败率你已经见过了。真正需要你动手计划的，只剩下一件事——复习。"],"art":"data:image/svg+xml;base64,","caption":"学习里唯一\"面向未来\"的环节是复习，也是唯一真正需要计划的（《学习的真相》22·学习计划）"},{"h3":"2复习的黄金原则：间隔越拉越长","paras":["复习不是\"多看几遍\"这么随意。它有一条黄金原则，叫递延时间间隔——每次复习之间的间隔，一次比一次拉长。第一次复习必须当天完成，这是全部复习习惯里最重要的一条，没有例外，哪怕当天再忙，也至少闭上眼睛把今天学的回忆一遍；第二次，隔一天（今天学、后天复习）；第三次，隔一周或一个月；第四、第五次，更久。这正是大名鼎鼎的艾宾浩斯遗忘曲线最重要的应用。","回报大得惊人：两三次复习，就足以打败所有不复习的同学。因为一个几乎荒诞的事实是——高达七成以上的人，终生都没有复习的习惯。你只要有，就已经赢过七成人。而故意把复习拖到远期，还藏着一个额外好处：等你隔很久再回头看它，这个旧知识点会不得不和你后来学到的新东西结合起来，织成一张更结实的网——就像一根旧链条被你牵着穿过时间，最终和未来的许多链条连成一片。"],"art":"data:image/svg+xml;base64,","caption":"递延时间间隔：第一次当天，之后越隔越久（《学习的真相》22·艾宾浩斯遗忘曲线的应用）"},{"h3":"3非必要不做计划——靠两个习惯顶上","paras":["为什么只计划复习？因为制定、执行、完成计划本身是件精神压力很大的事——一次计划失败，就会削弱你下次继续做计划的意愿。所以书里立了条原则：非必要不做计划。计划做得越多，越注定什么都完不成，最后干脆不做了。要让\"大多数事情不需要计划\"，得先养成两个独立工作时的好习惯，替你把计划顶掉。","其一，日常时间布局习惯——也就是番茄工作法。把 30 分钟当成一个不可中断的时间块：25 分钟完全集中，5 分钟休息，连做四个之后多休息一次。两条铁律不能破：①不存在\"不完整的番茄时间\"，哪怕在第 24 分钟被打断，这个番茄也直接作废；②一次必须连续完成四个。（注意：趴着打盹、翻网站、看邮件都不算休息，你得站起来走动走动。）","其二，突击时间安排习惯——一切需要突击的工作，都安排在最初，而不是最后。这是把\"临时抱佛脚\"变成\"计划内突击\"的唯一方式：一开学就把该背的概念先背下来、做题从最难的开始。这两个习惯一旦固化，一个人的执行力就会变得超强，而绝大多数事情从此按部就班、根本用不着计划。"],"art":"data:image/svg+xml;base64,","caption":"两个独立工作习惯替你顶掉大部分计划（《学习的真相》22·学习计划）"},{"h3":"4怎么判断\"做得够不够好\"？给自己一张检查表","paras":["计划归计划，还有个更底层的问题：你凭什么知道自己该复习什么、做得够不够好？靠的是脑子里那把尺——书里叫判断依据。所谓\"元认知\"（对自己思考的思考），说穿了就是一个又一个针对不同情况的判断依据。最惨的不是没有判断依据，而是脑子里装着一个错误的判断依据，还照着它得出错误结论。","好的判断依据从哪来？从清晰准确的定义来。作者给自己下过很多定义——作者、老师、投资人——但最有用的一个是\"我其实是个服务者\"。这个定义一出来，判断依据就自然浮现：我做的东西、我提供的服务，是否真的有用。还有一条原则永远好使：除了最重要的之外，剩下的都不重要——先把最重要的那件做好，文采、幽默都是次要的。","再往下，判断依据就细化成一张检查列表：一条条列出\"要做到有用，具体得满足什么\"，而且永远可以继续补充、修订。这一点很关键——检查列表越完善，元认知越强；自检列表越完善，自我认知越强。它压根不需要什么额外的智商。甚至我们平时说的\"品味\"\"审美\"，本质上也只是一张张被反复筛选、补充、修订过的检查列表而已。你的学习计划要不要复习这一项、复习到什么程度算过关，最终都由这张表说了算。"],"art":"data:image/svg+xml;base64,","caption":"定义 → 判断依据 → 检查列表，一张能不断修订的自检表（《学习的真相》23·判断依据）"}],"quote":"\"真正有效的学习计划其实非常简单，因为它只需要计划复习任务就行了。\"","quoteSrc":"—— 《学习的真相》22「学习计划」。学习里只有\"面向未来\"的环节才需要计划，符合这个标准且最重要的，就只剩\"复习\"。","reflect":[{"q":"回想上一次你\"计划完成了、成绩却没上去\"的经历——你的计划里，是不是也只列了\"什么时候做什么\"，却压根没安排\"什么时候复习\"？如果重来一次，你会在哪几天写上\"复习\"？","hint":"没有标准答案，写在你自己的本子上。提示：把\"当天第一次复习\"排进去，往往比多刷一套新题更值。"},{"q":"给你正在学的一样东西，试着写一句判断\"我学得够不够好\"的话——只要一句。写完再问自己：\"除了这一句，剩下的是不是都没那么重要？\"","hint":"没有标准答案。比如学英语，一句判断依据可以是\"我能不能不查词典读懂一段真实的英文\"。有了它，你就知道该往哪使劲。"}],"actionTitle":"🎯 行动卡 · 本周","action":"做一次\"只计划复习\"实验：找一个纸质日历本（书里特意说，纸质版比电子日历好用）。接下来一周，每天学完，只做两件事——①当天就把今天学到的最重要的一点，闭眼回忆一遍并在日历上记下来；②翻到\"隔一天\"和\"隔一周\"那两页，各写上今天的日期，作为复习提醒。不列别的任务，就管复习这一件。一周后回头看：这七天里，你有几次真的在到期那天完成了复习？记住那个数——只要你做到了两三次，你已经赢过了七成从不复习的人。"},"24-stuck":{"id":"24-stuck","kicker":"成长读本 · 学习的真相","title":"越往前学，越容易","hook":"想象你是个拆弹专家。你找到了炸弹，也知道怎么拆、怎么克服恐惧。可你最怕的是什么？最怕眼前这颗炸弹，用某种你看不见的方式，偷偷连着另一颗你根本不知道在哪的炸弹。\n 有些东西学起来特别费劲，根本原因就和这个差不多——不是它有多复杂，而是有一根你没看见的线，把它和别处连在了一起。这一篇，就来找出那几根线。","sections":[{"h3":"1再复杂的东西，都是简单拼出来的","paras":["先把一件事想清楚：一切的复杂，都是由许多个简单构成的。再复杂的东西，只要构成它的每个零件都很清楚、零件之间的连接也很明确，那它其实依然是简单的。","回到\"知识\"这个模型——所有的知识都由两个要素构成：一个是模型（一个个概念），一个是模型之间的关联。为了能反复利用它们去搭出更大、更灵活、更有用的东西，每一个子模型都必须、也只能是简单的。人类之所以了不起，正是因为进化出了语言之后，又意识到\"简单、毫无歧义\"有多重要，于是在各个领域造出了对应的人工语言。所以到最后，真正有用的东西，只能是简单的。既然如此，那\"学不会\"到底卡在哪儿？"],"art":"data:image/svg+xml;base64,","caption":"知识 = 简单的模型 + 模型之间的关联；两者都清楚，复杂就还原成简单（《学习的真相》24·学习障碍）"},{"h3":"2真正的障碍，是那根看不见的线","paras":["答案有点反直觉：真正构成学习障碍的，不是复杂本身，而是那些原本也很简单、却被隐藏起来的关联。它们分两种。一种叫隐含的关联——所有人都没察觉、但确实存在。比如仅仅几十年前，压根没人意识到\"所有知识在大脑皮层上其实同处一张网\"，于是学校想当然地分科，学生理直气壮地偏科，\"文科生讨厌科学、理科生回避历史\"的偏见到处都是；被它影响的人终身吃亏，却毫无察觉。","另一种叫未察觉的关联——因为某个人缺了某项训练，所以他没看见。最典型的例子是几何和画画：几乎所有形状都是由曲线构成的（连直线都只是\"曲度为零的曲线\"），一切完美的图形都跟完美的圆有关，透视则是在平面上画出立体的基础技法——几何是一切绘画和设计的必须。这些连学龄前的孩子都能懂一点，可很多想把画画好的人，从不知道自己该去补一点几何。缺了这根线，画出来的东西就是没法优美。你以为的\"没天赋\"，很多时候只是\"没看见那根线\"。"],"art":"data:image/svg+xml;base64,","caption":"未察觉的关联：想画好的人盯着画笔，却没看见画画偷偷连着\"几何\"（《学习的真相》24·几何影响绘画）"},{"h3":"3越难的，往往是\"复合技能\"","paras":["那些给人感觉最复杂、最难学的东西，基本都是复合技能——很多个能力叠在一起。最经典的例子就是写作：几乎所有人都花了十多年，认了足够多的字词，学过、练过、甚至考过几乎所有修辞手段，读过无数经典，结果绝大多数人还是写不出、写不好，到最后甚至怕写任何东西。","为什么？因为写作远不止\"语文\"这一项。光识字不够，光懂修辞不够，光有语文知识也不够——它同时还需要观察力、感知力、通感、思考力、组织力、表达力、沟通力……而且每一项都得足够强。所以，如果一位老师把作文课上成了语文课，所有努力最终都会白费。（《学习的真相》的作者讲过多年作文课，坚持不讲语法、不讲文采，为此被学生投诉过无数次，说他\"不务正业\"——可他干的才是正事。）那么，怎么对付这种\"复合\"带来的难度？答案你其实早就知道了，很简单也很直接：学得越多越好。别被别人吓倒——你天生就是一台基于记忆的超强推理机器，具备学会任何东西的潜能。"],"art":"data:image/svg+xml;base64,","caption":"写作不是单一技能，而是多种能力叠加的复合技能——把它当\"语文\"就必然失败（《学习的真相》24·复合技能影响写作）"},{"h3":"4那些\"没定义就用\"的词，最坑人","paras":["还有一种更隐蔽的障碍，叫前置引用。这个词借自电脑的报错：写程序时有条铁律——用一个变量之前，必须先声明它。你得先告诉电脑\"有这么个东西\"，它才能处理这个东西；一旦碰到没提前告诉过它的东西，电脑就直接报错。很多被学生认为艰难的科目，就是在关键点上藏着这种前置引用，而且最基础的地方，才是重灾区。","看看这些天天挂在老师嘴上的话：\"好好想想\"——可十多年里，没有一个老师认真定义过\"想\"是什么、该怎么想；\"你太不努力了\"——他也没告诉过你什么叫努力（其实努力就是\"短时间内足量重复\"）；\"这孩子基础太差\"——他从不需要说清\"基础\"到底指什么（其实基础就是\"那些只能靠逼迫才能习得的最少必要知识\"）。全是前置引用：用了一个从没定义清楚的词来要求你。它无所不在。那怎么解？其实和前面一样：千万不能放弃，无论如何继续学下去——你学得越多，知识网里的节点就越多，更多的节点会反过来集体帮你解开之前卡住的疑问。老人们常说的\"等你长大了就明白了\"，讲的正是这件事。"],"art":"data:image/svg+xml;base64,","caption":"前置引用无所不在，最基础处最多；解法是补上定义 + 继续往前学（《学习的真相》24·前置引用）"}],"quote":"\"各式各样的学习障碍全部加起来，其实只需要一个统一的应对策略：学得越多越好——学得越多，就越容易。\"","quoteSrc":"—— 《学习的真相》24「学习障碍」。隐含关联、复合技能、前置引用，看着是三种障碍，解法却是同一个：继续往前学，更多的节点会回头帮你解开旧的卡点。","reflect":[{"q":"回想一件你一直\"学不好\"的事——它真的是因为你笨，还是可能缺了一根你没看见的线（就像画画缺几何）？如果要找那根线，你会先去补哪一块？","hint":"没有标准答案，写在你自己的本子上。提示：越是\"怎么练都不见效\"的地方，越可能藏着一个未察觉的关联，而不是你的天赋问题。"},{"q":"最近有没有大人对你说过\"你要好好想想 / 你不够努力 / 你基础差\"？挑一句，试着把那个词换成清楚的定义——换完之后，你是不是更知道具体该做什么了？","hint":"没有标准答案。比如把\"不努力\"换成\"短时间内足量重复\"，你立刻能问自己：这周我在这件事上，够不够\"短时间、足量、重复\"？"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周当一回\"卡点侦探\"。遇到一个学不下去、想放弃的地方，先别死磕原地，做两步——①揪词：把卡住你的那句要求里\"没定义清楚的词\"找出来（\"好好想\"\"努力\"\"打好基础\"都算），给它一个你自己的清楚定义；②补线：往前或往旁边多学一点——去查这个知识点的来龙去脉（历史、人物传记里常藏着答案），或者补上它偷偷依赖的前一课。一周下来，记录你一共解开了几个卡点，以及每个是靠\"补定义\"还是\"往前多学\"解开的。你会亲眼看到：卡住，几乎从来不是因为笨，而是差了一根线。"},"25-be-a-producer":{"id":"25-be-a-producer","kicker":"成长读本 · 学习的真相","title":"从一开始，就当生产者","hook":"你今天玩的游戏、看的视频、穿的鞋、用的笔——全部是别人做出来的。抽象地看，到最后，这世界只有两种人：一种叫生产者，一种叫消费者。人类天生就是消费者，没有谁一出生就会做东西；学习，是获取生产能力的唯一来源。这一篇讲一个简单到大多数人不敢相信的决定：从第一天起，就把自己定位成\"做东西的人\"。","sections":[{"h3":"1两种人，以及生产者里的两种人","paras":["生产者里面，又只有两种：参与者和组织者。绝大多数人最终都成了参与者——不是因为不聪明，而是因为生产永远是复合技能，可他们被教育成了\"专才\"，还引以为豪。专才再厉害，也只能把一个环节做到极致；只有通才才能胜任组织：生产要统筹，销售要统筹，财务、人手也要统筹；供应商之间要协调，部门之间要协调；上下级、同事之间还有一堆人际关系要洞察。","书里举了个例子：俞敏洪的厉害之处，不仅在于讲课讲得好，更在于卖课卖得好。很多离开新东方去\"创\"业的名师并不成功，根源不是没创新，而是他们只是专才。用一句话概括这个差别：通才可以写剧本，专才了不起可以改剧本。"],"art":"data:image/svg+xml;base64,","caption":"人类天生是消费者；生产能力只能靠学习获得，而组织生产需要复合技能（《学习的真相》25·生产导向）"},{"h3":"2差别只有一个：把目标定在\"造\"","paras":["还记得学习的四个子模型吗——学、练、用、造。生产者和非生产者对学习的认知，关键区别简单得吓人：生产者从一开始，就以并且只以\"创造\"为目标。对他们来说，创造就是应用；为了造，就得练得更多；为了造，就只能学得更多——因为创造本身就是复合技能，创造需要通才。","反过来看那句你可能常听到的话：\"好好学习，才能找到好工作。\"书里说，这是最可怕的庸才修炼法——把天才打磨成庸才，一句话就够了。它把学习的目标从\"造\"降到了\"被别人用\"。还有一个要一起装进脑子的观念：所有努力的受益者，首先是自己。你学习、你锻炼，都不是为了家长、老师或考试；将来就算先从参与生产做起、拿薪水打工，也依然是在为自己干活。这个观念的有无，直接影响一个人的\"前/钱途\"。"],"art":"data:image/svg+xml;base64,","caption":"学练用造：目标钉在\"造\"，前面的学、练、用会被自动拉高（《学习的真相》25·生产导向）"},{"h3":"3你已经有生产的本钱了：复述 + 试错","paras":["\"生产\"听着遥远，其实你现在就有两样本钱。第一样是复述——把学到的、看到的，用自己的话重新讲出来，这是最基础、最自然且零成本的生产：它的生产资料是最便宜却又最复杂灵活的自然语言，而且复述本身就要动用一堆复合技能。文字创作能力，只能建立在复述能力之上——很多人上了十六年学却从没创作过任何东西，因为他们的学习模型里从来没有\"创作\"这个目标。","第二样是天生的：试错能力。大脑天生就是贝叶斯推理机——试一下，看结果，按新证据调整，再试。很多著名产品就是这么试出来的：李维斯本来是做帐篷的，淘金工人想要磨不破的裤子，才有了牛仔裤；可口可乐本想做解酒饮料，一次误用了碳酸水才发现好喝；盘尼西林、阿司匹林、X 射线，都是误打误撞的结果。不过只会试错还不够，得不断补充判断依据。书里给了个出人意料的来处：上市公司的财报——识字加上加减乘除就能读，而天下有效的商业模型简单到只有三个词：收入 − 成本 = 利润，再看利润有没有不断增长的空间。随便读几份，判断依据就悄悄攒起来了。"],"art":"data:image/svg+xml;base64,","caption":"大脑天生是贝叶斯推理机：试错 + 不断补充判断依据 = 越来越高效的生产（《学习的真相》25·生产导向）"},{"h3":"4好消息：做东西，从来没有这么便宜过","paras":["你可能会想：做东西不是需要很多钱吗？趋势恰恰相反——资本对生产的重要性和必要性正在逐步降低，而且已经低到令人难以置信。历史上能换来财力的无非三样：暴力、魅力、智力；从趋势上看，智力的重要性在不断增加，暴力在不断贬值。更重要的是，在金融市场高度发达的世界里，真正优秀的生产者不可能找不到财力的支持——会有投资人抢着来投。","生活成本本身也一直在降。书里用\"照明\"举例：4000 年前的古巴比伦，用芝麻油点灯，一个人干一天活只换得来 10 分钟照明；17 世纪用上鲸鱼油，涨到 1 小时；18 世纪的煤油，涨到 5 小时；而现在，一天工作能买到的照明时间，是 200 年前的 2 万倍。所以家长们原本大可不必焦虑，你也一样——报纸杂志上写满\"中年危机\"，但书里的判断很干脆：真正合格的生产者不可能有什么中年危机，他们只能是后半场获胜者。而解决方案简单到绝大多数人不敢相信：从一开始，就把自己定位为生产者。"],"art":"data:image/svg+xml;base64,","caption":"一天工作能换来的照明：10 分钟 → 1 小时 → 5 小时 → 2 万倍——做东西的门槛一直在暴跌（《学习的真相》25·生产导向）"}],"quote":"\"生产者从一开始，就以创造并且只以创造为目标。\"","quoteSrc":"—— 《学习的真相》25「生产导向」。学练用造，目标钉在哪一格，决定了前面每一格的深度；而从消费者变成生产者，第一步只是换一个自我定位。","reflect":[{"q":"数一数：这一周你\"消费\"了多少别人做的东西（游戏、视频、零食、文具……）？再数一数，你\"生产\"过几样给别人用、看、玩的东西？这个比例，你自己满意吗？","hint":"没有标准答案，写在你自己的本子上。提示：天生是消费者不丢人，人人如此——但比例可以从今天开始，一点点挪。"},{"q":"\"好好学习，才能找到好工作\"和\"好好学习，才能做出自己想做的东西\"——这两句话，会把一个人带到多么不一样的地方？你打算用哪一句当自己的？","hint":"没有标准答案。前一句的终点是\"被挑选\"，后一句的终点是\"去创造\"——而为了造，你自然会学得更多、练得更多，谁也不用逼你。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周完成一次\"消费者 → 生产者\"的翻转：挑一样你最爱消费的东西（一个游戏、一类视频、一本漫画、一个玩具……），自己动手做一个最小版本——画一张游戏关卡设计草图、写一个 60 秒视频的脚本、画一页四格漫画，或者把这周学会的一个知识点写成一页\"别人能看懂的小说明\"。只有一条硬要求：做出来之后，交给一个真实的人去用、去看，然后记下两件事——①对方给你的一个反馈；②做的过程中你发现的一个\"原来我还不会\"的地方。你会体验到：只当用的人，永远不知道做的人在想什么；而做过一次的人，连消费的眼光都会变。"},"26-overall-planning":{"id":"26-overall-planning","kicker":"成长读本 · 学习的真相","title":"烧水的时候，把杯子洗了","hook":"想泡一壶茶：洗开水壶要 1 分钟，烧开水要 15 分钟，洗茶壶 1 分钟，洗茶杯 2 分钟，拿茶叶 1 分钟。一件一件做，20 分钟。数学家华罗庚在 1965 年的一本小书《统筹方法平话及其补充》里给出的答案是：16 分钟。这个例子后来进了小学六年级的语文课本，人人都学过——可你看看有多少大人在厨房里忙得焦头烂额，就知道\"学过\"和\"会用\"隔着多远。省下的 4 分钟去了哪？这一篇讲清楚。","sections":[{"h3":"1统筹，只研究两件小事","paras":["华罗庚的做法：先把任务拆成若干个步骤，每步用时都算得出来，然后研究步骤之间的关系——这就是统筹（统一筹划）。别被这个词吓到，它到最后只研究两件小事：一个叫串联，一个叫并联。","串联：哪些步骤必须分先后？洗开水壶必须放在烧开水之前，这个顺序不能乱。并联：哪些步骤可以同时进行？洗茶壶、洗茶杯、拿茶叶这三件事不分先后，关键是——它们全都可以塞进烧开水的那 15 分钟里，一点不耽误事。于是 20 分钟变成 16 分钟。书里把结论说得很直白：到最后，节省时间的核心来自于并联。统筹后来甚至成了一门专门的学科，可它的核心简单到六年级学生都能实践——伟大的思想都是简单的。"],"art":"data:image/svg+xml;base64,","caption":"同样五个步骤，只是重排：必须分先后的串联起来，能同时做的并联进等待里（《学习的真相》28·效率至上）"},{"h3":"2一个句型，随身带走","paras":["日常生活里，善于寻找任务之间的并联关系，能让自己多做不知道多少事。全部诀窍浓缩成一个句型：\"在做……的同时，把……也给做了。\"","书里给的例子都很日常：当天整理笔记的同时，把第一次复习也给做了；想学什么新东西，买回来外语版教材研读——学那个东西的同时，把外语阅读也练了；散步的同时听有声书；甚至小朋友想玩游戏——可以玩，但必须玩英文版。到最后，大家之间的差别不就是：同样的时间里，谁做的事更多。"],"art":"data:image/svg+xml;base64,","caption":"节省时间的核心来自于并联——句型：\"在做……的同时，把……也给做了\""},{"h3":"3统筹最怕的，不是不会排","paras":["实际操作里，统筹真正的难度来自任务拆分是否合理：拆得太细没必要；拆分不当，就分辨不出哪些步骤原本可以并联，白白错过省时间的机会。","还有一种更可怕的形式：压根儿没意识到某个必要步骤的存在。比如很多人的学习计划里，干脆就没有预习和复习，只有突击。这不是智商问题——琢磨串联并联真的不难——可关键步骤都被忽略了，统筹得再认真也没用。上一篇讲过\"仅仅按时间罗列任务，从来不是有效的学习计划\"，现在可以补全了：没有统筹就没有计划，只有统筹才是真正有意义、真正有效的计划。同理，仅仅带上一块表、会看时间，也并不能自动建立有意义的时间观念。"],"art":"data:image/svg+xml;base64,","caption":"任务拆分最可怕的失误：没意识到关键步骤的存在（如学习计划里没有预习和复习）"},{"h3":"4效率的尽头：学习就是攒时间","paras":["为什么要把磨练效率放到重视度的最高等级？因为缺乏效率最耽误事——你不断提高效率，在同样的时间里做更多的事，就是实实在在提高自己未来的赚钱能力；而经济独立是思想独立的基础。比缺效率更糟的只有一样：缺长期观念。可长期观念偏偏没法天生——大脑是为生存设计的，天生短视；而且时间的\"感受速度\"人人不同：对 5 岁的孩子，未来一年相当于已有人生的 20%；对 12 岁的你，约 8%；对 50 岁的人，只有 2%。所以人们总是不由自主地低估远期收益、高估近期损失——说教也没用，\"少壮不努力\"从小学一年级背起，绝大多数人照样老大徒伤悲。","书里给的解决方案只有一个：从爱上学习开始。因为学习是天下真正的速成——你识字，相当于用几年就走完人类几万年，一步跨到公元前 3500 年；你学几个阿拉伯数字，它们公元 1200 年左右才传到欧洲、1500 年才被全面采用；你在小学理解的负数，人类到汉代《九章算术》才有；你九年级学的能量守恒，是再过 1700 多年、由焦耳等十几位科学家才发现并证明的。每次你学到一个新知识，对你只是一小步，可那是人类的一大步——直接拿过来。所以学习就是攒时间，甚至是攒命；而学习会提高效率，效率反过来又促进学习——只有这样滚出来的积累，才能滋生真正的长期观念。"],"art":"data:image/svg+xml;base64,","caption":"\"世界上真正的速成，只不过是朴素的学习\"——你的一小步，都是人类的一大步（《学习的真相》28）"}],"quote":"\"到最后，节省时间的核心来自于并联。\"","quoteSrc":"—— 《学习的真相》28「效率至上」。统筹只研究两件小事：串联与并联。人们那么小就学过，却从来没有真正重视过——这么重要的东西，竟然真的这么简单。","reflect":[{"q":"回想你今天早上从起床到出门的全过程：拆成小步骤，哪些必须分先后（串联）？哪些其实可以塞进\"等待的缝隙\"里同时做（并联）？照华罗庚的算法，你能省出几分钟？","hint":"没有标准答案，写在你自己的本子上。提示：先找\"最长的那段等待\"（烧水、加热、下载、排队），能往里塞的事越多，省得越多。"},{"q":"\"学习就是攒时间\"——你去年学会的东西里，哪一样是人类花了几百年甚至几千年才搞明白的？如果没人教、不上学，你自己摸索要多久？","hint":"没有标准答案。提示：负数、阿拉伯数字、能量守恒……随便挑一个算一算，你会发现\"朴素的学习\"是世界上兑换率最高的交易。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周做一次\"统筹改造\"实验：挑一件你每周至少做三次的日常流程（写作业的全过程、早上出门、帮家里做一顿饭都行）。①把它拆成小步骤，写下每步大约用时；②标出哪些必须分先后（串联）、哪些可以同时做（并联）；③找出最长的那段\"等待\"，把能并联的事塞进去；④按新顺序做一遍，用表计时。硬要求：像华罗庚那样写出两个数字——\"旧顺序 __ 分钟 → 新顺序 __ 分钟\"。顺手再检查一件事：这个流程里有没有被你漏掉的关键步骤（比如作业流程里的\"检查\"）？周末把省下的分钟数乘上一年要重复的次数——那就是你攒下的第一笔\"时间存款\"。"},"27-define-it":{"id":"27-define-it","kicker":"成长读本 · 思考的真相","title":"你脑子里有一张概念表","hook":"嗓子哑、舌头起泡、有点发烧——家里长辈多半会说：\"上火了，降降火。\"可\"火\"到底是什么？它在身体的哪里烧？为什么凉茶能浇灭它？你大概答不上来。有意思的是：所有有行医执照的医生，早就把\"火\"这个概念从脑子里删掉了，换成了另一个词——炎症。\"删掉一个概念\"听起来很奇怪吧？这一篇讲思考的第一块地基：定义。它简单到只是一个等号，却决定了你会不会思考。","sections":[{"h3":"1思考，最基础的只有四个词","paras":["日常生活里的思考，真的没有多复杂。书里说，思考需要考虑的最基础要素主要只有四个：定义、分类、比较、因果。更准确地讲，思考的核心其实都是概念——每个概念都需要定义得足够清楚，然后概念之间可能需要分类，可能相互比较，可能构成因果关系。四个词，第一个就是定义。","而定义的核心，只不过是一个等号：等号左边是概念，右边是描述——某个概念究竟是什么意思。就这么简单。可你马上会看到，绝大多数人脑子里的等号，右边要么是空的，要么塞着一团说不清的东西。"],"art":"data:image/svg+xml;base64,","caption":"思考的四要素，第一个是定义；定义的核心只是一个等号（《思考的真相》1.1）"},{"h3":"2教科书，其实是一条概念链","paras":["教科书里的定义往往只有一个，并且要求描述精确且完整。物理课本里，加速度 = 速度变化量与发生这一变化所用时间的比值。那\"速度\"呢？速度 = 位移与发生这个位移的时间之比。\"位移\"呢？由初始位置到末位置的有向线段构成的矢量。\"矢量\"呢？有大小和方向的物理量。一环扣一环，谁也不含糊。","每一个学科都是这样：由一个又一个相互关联的概念构成的，每个概念都有精确且完整的定义。所以每次你学会一项新技能、掌握一门新学科，本质上就是往脑子里新增了很多概念。比如你只要操作过 Excel 表格，就可能听说过 CRUD——创建 create、读取 read、更新 update、删除 delete，四个新概念就这么进了你的脑子。记住这四个词，下一节马上要用。"],"art":"data:image/svg+xml;base64,","caption":"想说清\"加速度\"，就得先说清速度、位移、矢量——教科书是一条精确且完整的概念链"},{"h3":"3你脑子里的那张表，也能增删改","paras":["书里给了一个特别好用的模型：每个人脑子里都相当于有一张概念表，每一条记录就是一个概念。你实践的时候，是在读取（调用）某个概念；你学习的时候，是在新建、更新、删除某些概念——正好就是上一节的 CRUD。","这不是打比方，历史上真的发生过。大约从 1650 年开始的 100 多年里，人们脑子里有个概念叫燃素：一切可燃的东西都是因为含有燃素——木头含燃素所以可燃，石头不含所以不可燃。后来法国化学家拉瓦锡把这个概念删除了，而这次删除是一个分水岭，标志着近代化学的崛起。再看开头那个\"火\"：舌头起泡、嗓子哑、发烧发热，古人都归因于\"火太大了\"；现代医学发展后，人们知道这个概念应该更新成\"炎症\"——然后就能针对不同部位的炎症，用不同的药物去消炎。删掉一个错的概念，更新一个旧的概念，整门学科、整套医术就此改写。"],"art":"data:image/svg+xml;base64,","caption":"学习 = 对概念表做新建、更新、删除；实践 = 读取。拉瓦锡删掉\"燃素\"，删出了近代化学"},{"h3":"4定义的关键，只有两条","paras":["那怎么判断一条定义合不合格？书里说，关键主要只有两个部分：第一，等号左边的概念要必要——没必要的就要删掉（像燃素）；第二，等号右边的描述要准确——所谓准确，就是毫无歧义；如果有歧义，就要反复更新，直至毫无歧义。你看，定义的关键没有多复杂。","当然，生活中很多概念可以有若干个定义——重要的事物往往有很多方面、很多看待角度。比如时间：物理学上，它是一种尺度，是标量，包含时刻和时段两个概念；而生活中人们常说\"时间就是金钱\"，李笑来则常说\"时间是一种生产资料\"——这些都是从另外一个角度重新定义时间。不过，无论在学术上还是在生活当中，要求都一模一样，只有两条：第一要必要，第二要准确。但凡哪一条做不到，那就需要更新，甚至删除。"],"art":"data:image/svg+xml;base64,","caption":"合格的定义只查两条：左边必要、右边准确（毫无歧义）——做不到就更新，甚至删除"}],"quote":"\"很多人宁愿死，也不肯思考，并且，他们中的大多数的确也就那样死掉。\"","quoteSrc":"—— 英国哲学家罗素，《思考的真相》1.1「定义」开篇引。思考的第一步小得出奇：把你正在用的那个词，定义清楚。","reflect":[{"q":"挑一个你天天挂在嘴边的词——\"内卷\"\"情商\"\"运气\"都行——试着写出等号右边的描述，再读给同学听：他理解的和你想说的，是同一个意思吗？","hint":"没有标准答案，写在你自己的本子上。提示：如果两个人的理解不一样，说明描述还有歧义——按书里的做法，反复更新，直至毫无歧义。"},{"q":"你的概念表里，有没有一条像\"火\"一样该更新、或像\"燃素\"一样该删除的记录？想想小时候深信、后来发现不准确的说法。","hint":"没有标准答案。提示：发现\"我以前理解错了\"不是丢脸的事——拉瓦锡删掉一个概念，删出了近代化学；有行医执照的医生，人人都做过这次更新。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周当一次\"概念表管理员\"：拿一页纸分三栏——新建 / 更新 / 删除。每天从课本、聊天或视频里挑 1 个概念登记：新学会的写进\"新建\"栏，并用自己的话写出等号右边的描述；发现自己以前理解得不准的写进\"更新\"栏（旧描述 → 新描述）；说不清楚、也找不到用处的写进\"删除\"栏。硬要求：每条登记时都检查两件事——左边必要吗？右边毫无歧义吗？周末数一数三栏各有几条，挑\"更新\"栏里最意外的一条讲给家人听。"},"28-sort-it-out":{"id":"28-sort-it-out","kicker":"成长读本 · 思考的真相","title":"不重不漏，才算想全了","hook":"训练人工智能，听起来是全世界最尖端的事吧？书里讲了个有意思的对照：AI 需要大数据，而在把大数据喂给 AI 之前，得先\"清洗数据\"，术语叫打标签——说白了，就是分类。再看另一头：图书馆是人类最古老的知识机构之一，它的核心叫情报学，而情报学的核心，也只不过是分类。最新的 AI 和最老的图书馆，底层竟是同一件小事。这一篇讲思考的第二块地基：分类。好的分类，要求只有两条——但大多数人两条都没做到。","sections":[{"h3":"1有些概念，是\"一群概念\"","paras":["上一篇说过，思考的基础要素有四个：定义、分类、比较、因果。定义清楚之后，你会发现有些概念是集合概念——由多个确定的元素或者其他概念构成的整体。比如\"灵长类动物\"就是一个集合概念，里面装着很多动物类别：猴、猿，以及人类。","对集合概念里装着的这些概念，为了分析和决策，我们经常需要做的工作就是分类。听起来平平无奇？往下看——一个流传很广、印在经济学书籍里的分类，马上就要翻车了。"],"art":"data:image/svg+xml;base64,","caption":"集合概念 = 由多个概念构成的整体；对它做的最常见工作，就是分类（《思考的真相》1.2）"},{"h3":"2要求一：合理——子类别互不重合","paras":["某些经济学书籍里常常提到\"生产四要素\"：土地、人力、企业家才能、资本。看起来一本正经，可它没做到良好分类的第一个要求——合理，即各个子类别之间应该互不重合。","你看：资本能买到其他三个要素中的任何一个。资本可以买到土地，也可以买到人力；只要允许，企业家才能也不是不行——聘请 CEO，不就是购买企业家才能吗？那么请问，资本怎么可以与其他三个要素并列呢？就像把\"水果\"分成\"苹果、香蕉、能买水果的钱\"——第三个类别根本不在同一层，跟前两个处处重合。"],"art":"data:image/svg+xml;base64,","caption":"\"生产四要素\"翻车现场：资本可以买到土地、人力、企业家才能，怎么能与它们并列？"},{"h3":"3要求二：完整——加起来等于全部","paras":["良好分类的第二个要求叫完整：所有的分类加起来，应该等于全部。灵长类动物的合理分类应该是猴、猿、人，以及\"其他灵长类\"——没有\"其他\"这个类别，就不完整。回到生产四要素：如果因为资本跟别人重合、只好把它删掉，那么剩下的土地、人力、企业家才能三个类别，又无法构成完整的分类。合理、完整，两头都不及格——无论从哪个角度望过去，这个分类都实在太糟糕了。","当然，还有更糟的：把原本不属于某个集合概念的东西硬塞进去。经典案例是前苏联科学家李森科——生生捏造出一个\"获得性遗传\"学说，包装成\"米丘林生物学\"，硬塞进\"科学\"这个集合概念里，当作其中一个类别。或者反过来，把明明属于的剔除出去：逻辑训练原本应该属于基础教育，可一些人认为它不该属于，于是好几代人都在缺了这一块的教育下长大——如果不自己挣扎一下，整个生活都会因此变得乱七八糟。"],"art":"data:image/svg+xml;base64,","caption":"完整 = 所有类别相加等于全部；比不完整更糟的，是往集合里乱塞、或把该在的踢走"},{"h3":"4\"想得全面\"，其实就是这两条","paras":["合理且完整，是良好分类的最基本要求，就这么简单。可是，这么简单的东西却异常重要。开头那个对照你还记得吧：图书馆的核心是情报学，情报学的核心只不过是分类；AI 崛起了，培养 AI 的核心基础工作之一——给数据打标签——竟然也还是分类。从最老的行当到最新的行当，底层是同一门功夫。","生活中所谓的\"思考全面\"，归根结底只不过是：分类是否足够合理，分类是否足够完整。分析一个问题，看到某个结果有很多原因——这些原因该如何分类？有没有什么类别没考虑到？要做判断了——判断标准该如何分类？有没有什么标准没考虑到？考虑一个事物——它到底有哪些方面？有没有什么方面没考虑到？这些问题本质都一样，全都是分类；既然是分类，就需要做到既合理又完整。下次有人夸你\"想得真全\"，你知道那其实是在夸什么了。"],"art":"data:image/svg+xml;base64,","caption":"分析原因、定判断标准、考虑方面——本质都是分类，都只查同样两条：合理、完整"}],"quote":"\"所谓的思考全面，归根结底，只不过是分类是否足够合理、是否足够完整而已。\"","quoteSrc":"—— 《思考的真相》1.2「分类」。两条要求：合理 = 子类别互不重合；完整 = 加起来等于全部。","reflect":[{"q":"你听过\"人分两种：努力的和懒的\"这类说法吗？用两条要求检查一下：有没有人既努力又偶尔犯懒（重合）？有没有人哪一类都放不进去（不完整）？它及格吗？","hint":"没有标准答案，写在你自己的本子上。提示：很多流行的\"人分两种\"，两条要求一条都过不了——识别出这一点，你就已经比说这话的人想得全面了。"},{"q":"看看你手机里的相册文件夹、书包里的分层，或者电脑里的文件夹——哪个分类里有\"能同时放进两个格子\"的东西？哪个分类缺一个\"其他\"？","hint":"没有标准答案。提示：找东西慢，常常不是因为东西多，而是因为类别重合（不知道放哪了）或不完整（有东西无处可放，随手一丢）。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周当一次\"分类质检员\"：挑三个你身边现成的分类——比如手机 App 的文件夹、书桌抽屉的分区、笔记本里的科目分栏。对每一个都只问两个问题：① 有没有两个类别互相重合？② 所有类别加起来等于全部吗（缺不缺\"其他\"）？把最不及格的那一个动手重新分一次，重分前后各计一次时：\"找同一样东西，原来花几秒，现在花几秒？\"周末把最大的那次提速讲给家人听——顺便考考他们：生产四要素错在哪？"},"29-compare-it":{"id":"29-compare-it","kicker":"成长读本 · 思考的真相","title":"选不出来，是因为还没比完","hook":"设想一个场景：高考之后，家里同时收到了三所学校的录取通知书。全家开会，讨论了三个晚上，谁也说服不了谁——爸爸看重排名，妈妈惦记离家远近，孩子只想去有喜欢专业的那所。听起来像\"人生难题\"吧？书里用一张小小的打分表，几分钟就算出了答案。秘密不在于聪明，而在于思考的第三个基础要素：比较。这一篇讲清楚：什么东西能比、拿什么去比、比不出来的时候到底卡在哪。","sections":[{"h3":"1能比较的前提：同一范畴 + 相同属性","paras":["两个事物之间之所以可以相互比较，条件有两个：首先，它们属于同一范畴；其次，它们拥有相同的属性。苹果和橘子可以比，因为它们同属\"水果\"这个范畴，于是可以比较同一个属性——哪个更好吃。","这两个条件看着不起眼，却直接接住了前两篇：范畴清不清楚，靠\"定义\"；属于不属于同一类，靠\"分类\"。定义、分类做好了，比较才有地基。很多争不出结果的\"哪个更好\"，其实在这一步就已经跑偏了——两样东西根本不在同一范畴，或者压根没说清在比哪个属性。"],"art":"data:image/svg+xml;base64,","caption":"可比 = 同一范畴 + 相同属性；缺一个，比出来的都是糊涂账（《思考的真相》1.3）"},{"h3":"2胡乱比较的第一个坑：不分主观和客观","paras":["比较原本并不困难，可生活里经常感觉并非如此。主要原因之一是：人们经常胡乱比较，压根不在意判断依据是主观的还是客观的。","判断依据可以分成两类。主观的——比如两件衣服穿在身上哪件更好看——倒也不是没用，但它本身不可争辩，你用它做出来的判断同样不可争辩：无论跟自己纠结还是与别人争辩，都没有太多意义。客观的——比如两个人谁更高——就完全不同了：身高可测量，相差多少可计算，可以被量化，可以被精确比较。所以说，判断依据最好是客观的。下次争\"哪个更好\"争到脸红之前，先停一秒问：我们用的依据，可争辩吗？"],"art":"data:image/svg+xml;base64,","caption":"主观依据不可争辩；客观依据可量化、可精确比较——比较从选对依据开始"},{"h3":"3依据不止一个？排重要性、给权重、算总分","paras":["当多个客观判断依据同时存在时，方法是：按重要性排列，分别给予不同的权重（所有权重加起来等于 100%），再按每个依据逐一打分，分数乘以权重求和，得到总分——总分一比，结论自现。","回到开头的三份录取通知书。先确定四个判断依据：学校排名、地理位置、专业设置、学费。假设认为排名最重要，给 40% 的权重；地理位置次之，30%；专业设置第三，20%；学费最不重要，10%。然后逐项打分：排名一项 A 校最高 10 分、B 校 8 分、C 校 6 分……每个依据都打完分、乘以权重、加起来，最终 A 校 8.2 分、B 校 7.9 分、C 校 7.4 分——A 校胜出。书里说得干脆：这里的核心其实就是比较，只要比较结果出现，决策就呼之欲出。吵三个晚上没结果的事，一张表算完了。"],"art":"data:image/svg+xml;base64,","caption":"四个依据 × 各自权重 → 三所学校的总分：8.2 / 7.9 / 7.4——争论变成了算术"},{"h3":"4第二个坑：判断依据，没法一次凑齐","paras":["胡乱比较还有另一个困境：判断依据这个东西，只能靠不断积累——谁都没办法从一开始就一下子获得或掌握所有判断依据。书里拿\"评价一部电影\"举例，认真做的话要参照一大串：类型、题材、风格、导演、演员等基本信息；导演、编剧、演员的能力体现；票房、评分、奖项等客观数据；剧情、人物、主题、情感等主观感受；还有社会影响、文化价值、创新意义等深层评价。","可日常生活中，人们是懒得做工的——99.99% 的情况下，人们给电影打的分，体现的不过是看完之后\"爽的程度\"而已。一旦要求自己客观，你就会体会到：比较虽然简单，工作量却非凡。这种困境不只在评电影时存在，在科学研究、公共决策、商业竞争这些更重要的领域里，判断依据的获取和使用更难、也更关键。它没有一次性的解决方案，到最后只能靠长期积累和持续更新——但反过来，这恰恰是终生学习、终生成长的动力：你多积累一个判断依据，就比昨天的自己会比一点。"],"art":"data:image/svg+xml;base64,","caption":"认真评一部电影要五层依据；而大多数打分只用了\"爽\"这一个——客观，是攒出来的"}],"quote":"\"只要比较结果出现，决策就呼之欲出。\"","quoteSrc":"—— 《思考的真相》1.3「比较」。前提：同一范畴 + 相同属性；依据：最好客观、可量化；多个依据：给权重、算总分。","reflect":[{"q":"回想你最近一次和同学争\"哪个更好\"（球星、游戏、手机……）却谁也说服不了谁——你们用的判断依据，是主观的还是客观的？如果换成客观依据，你们会先比哪一项？","hint":"没有标准答案，写在你自己的本子上。提示：吵不出结果的争论，多半是在用\"不可争辩\"的主观依据互相争辩——先把依据换掉，争论常常自动消失。"},{"q":"给你最喜欢的一部电影认真打一次分：五层依据（基本信息／主创能力／客观数据／主观感受／深层评价）里，你现在能写出内容的有几层？空着的那几层，说明了什么？","hint":"没有标准答案。提示：空着的层不是你的错——判断依据本来就只能靠积累。发现空层，恰好是\"下一步该学什么\"的地图。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周用权重打分表做一次真实的小决策——买哪本书、参加哪个社团、周末先做哪件事都行。步骤：① 先凭直觉在心里选一个，写下来盖住；② 列出 3–4 个判断依据，尽量客观；③ 按重要性给权重，加起来必须等于 100%；④ 逐项打分（1–10 分）、乘权重、算总分。最后揭晓：算出来的答案和直觉选的一样吗？如果不一样，看看是哪个依据把结果扳过去的——把这张表和这个发现讲给家人听。"},"30-trace-the-cause":{"id":"30-trace-the-cause","kicker":"成长读本 · 思考的真相","title":"先发生的，不一定是原因","hook":"期末成绩下滑，家里的判决几乎是秒下的：\"都是因为你天天玩手机。\"听起来很顺：先有玩手机，后有成绩下滑，一前一后，铁证如山？可你大概也见过另一种\"铁证\"——比赛那天正好穿了新球鞋，赢了，于是那双鞋成了\"幸运鞋\"。两件事一前一后发生，就能说前面那件是原因吗？这一篇讲思考的第四个基础要素：因果。它可能是四个要素里最难的一个——难到几乎撑起了整个科学。好消息是，书里给了一个只有四个问题的模板，普通人拿来就能用。","sections":[{"h3":"1原因在前，结果在后——但反过来不成立","paras":["先把顺序说死：当一个原因产生一个结果的时候，这个原因总是在前，结果总是在后。原因不可能迟到。","可是，\"在前\"只是原因的必要条件，不是充分条件——我们从小就被教育过：时间上的先后顺序，并不保证因果关系。新球鞋在赢球之前穿上，手机在成绩下滑之前就在玩，这些都只能说明\"它发生在前面\"，说明不了\"它导致了后面\"。把\"先发生\"直接当成\"是原因\"，正是日常生活里最常见、也最不被察觉的一步跳跃。上一篇你或许还记得：《把时间当作朋友》里也点过\"相关不等于因果\"这个陷阱——而这一篇，会给你一套自己动手查因果的办法。"],"art":"data:image/svg+xml;base64,","caption":"时间先后顺序，并不保证因果关系（《思考的真相》1.4）"},{"h3":"2查因果有多难？难到撑起了整个科学","paras":["从学术上来看，因果关系的探究从来都并不容易——甚至，因果分析几乎是整个科学的核心。为了确认\"a 到底是不是 b 的原因\"，各个领域的科学家们发展出了一整套专门的方法：平日里常见的观察法、实验法、统计分析之外，药学里普遍使用双盲验证和回溯研究，法律领域普遍认同谁主张谁举证的原则，经济学有回归分析，社会科学有随机对照试验、差分法，计算机领域有蒙特卡罗模拟……","这些方法有个共同点：理解上都不太困难，但是操作上都相当吃力——科学方法的实施过程，基本上都相当耗时、费力、伤财。绝大多数普通人不可能一一掌握，日常生活里个体的研究能力和生产资料都有限，于是常常干脆囫囵吞枣地采用专家获得的研究成果。这不丢人，这是现实。但生活里的问题实在太多，总有无法避免、要自己动手研究的时候——那怎么办？"],"art":"data:image/svg+xml;base64,","caption":"因果分析几乎是整个科学的核心——每个领域都为它专门造了工具"},{"h3":"3普通人的工具：四个问题，逐一自问自答","paras":["书里给出的办法，是一个提问式模板。如果把 a 和 b 放在一起，想探究它们是否是因果关系，就按顺序问四个问题：","第一问：a 真的是 b 的原因吗？如果不是，分析到此结束。第二问：如果 a 的确是 b 的原因，那么 a 是 b 的唯一原因吗？如果是，分析也结束了。第三问：如果 a 不是唯一原因，那么还有哪些原因？把它们全部罗列出来。第四问：既然 a 并不是 b 最重要的原因，那么最重要的原因到底是什么？——然后，答案就出来了。"],"art":"data:image/svg+xml;base64,","caption":"因果四问：两道\"出口\"提前收工，两道\"追问\"挖到真正重要的原因（《思考的真相》1.4）"},{"h3":"4简单，却已经超越绝大多数人","paras":["把开头那句\"都是因为你天天玩手机\"放进模板试试。第一问：手机真的是成绩下滑的原因吗？可能是。第二问：它是唯一原因吗？多半不是。第三问：还有哪些？睡眠不足、这学期内容变难、复习方法没跟上、考前状态……全列出来。第四问：最重要的原因到底是什么？——答案很可能不是\"没收手机\"三个字能解决的。你看，同一件事，凭感觉下结论和用四问过一遍，得到的是两个世界。","书里对这个模板的评价很克制，也很提气：这个提问流程，虽然非常简单，却相当够用。日常生活里的绝大多数因果分析，哪怕仅用这四个问题过一遍，就已经超越了绝大多数人的思考或者不思考——简单，却实用。你不需要蒙特卡罗模拟，你只需要在下结论之前，多问四个问题。"],"art":"data:image/svg+xml;base64,","caption":"简单却实用：仅用四个问题过一遍，就已经超越了绝大多数人的思考或者不思考"}],"quote":"\"因果分析，几乎是整个科学的核心。\"","quoteSrc":"—— 《思考的真相》1.4「因果」。原因在前、结果在后，但先后不保证因果；普通人的够用工具＝四问：是原因吗 · 唯一吗 · 还有哪些 · 哪个最重要。","reflect":[{"q":"回想一个你自己深信过的\"因果\"——幸运物、\"一喝凉水就生病\"、\"某某老师教得不好所以我这科不行\"……用四问过一遍，它能走到第几问？","hint":"没有标准答案，写在你自己的本子上。提示：很多\"深信\"在第一问就停了——它只是先发生，或者只是恰好一起出现。能走到第三问的，才值得认真列清单。"},{"q":"大人们也常用\"一句话因果\"下结论（\"成绩下滑就是因为手机\"）。如果让你用第三问和第四问帮这句话补全，你会往清单里加哪些原因？哪个最重要？","hint":"没有标准答案。提示：第三问的清单越诚实，第四问的答案越有用——找到最重要的原因，才知道该改的到底是什么。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周做一次\"因果四问\"侦探实验：收集 3 句你身边出现的\"一句话因果\"（自己说的、家人说的、同学说的都行，比如\"因为 __ 所以 __\"）。每句都在本子上过一遍四问：① 真的是原因吗？② 是唯一原因吗？③ 还有哪些原因？全部列出来；④ 最重要的原因是什么？记下每句话\"走到了第几问\"、清单里被你新挖出来的原因有几个。周末挑改判最大的一句，把你的四问清单讲给家人听。"},"31-decide-it":{"id":"31-decide-it","kicker":"成长读本 · 思考的真相","title":"决策，不是第五种本领","hook":"前四篇，你攒齐了四样工具：定义（左边必要、右边毫无歧义）、分类（不重不漏）、比较（同一范畴、相同属性）、因果（四问模板）。现在来一个反常识的消息：接下来要讲的\"决策\"，并不是第五种新本领。书里说得干脆——我们做的每一个决策，无论重要与否，背后所谓的思考，其实全都是这四个要素的组合应用。从选职业到选午饭，从买一辆车到买一支股票，全是同一条流水线。","sections":[{"h3":"1四个要素，有一条微妙的先后顺序","paras":["四个要素不是随便抓一个就用，它们之间有一条微妙的先后顺序：为了分析因果，就可能需要提前进行比较；在比较之前，就得先做到分类合理，才能基于同一范畴、同一属性进行比较；而为了分类合理，就要先做到定义足够清楚。倒过来读一遍就是流水线：定义 → 分类 → 比较 → 因果 → 决策。","当然，到最后全都是组合嵌套使用。比如找到种种原因之后，还要对各种原因再次归类——分为内部原因或者外部原因——然后相互比较，直到找到最重要的那个原因。工具不是用一次就收起来的，它们在一次决策里会被反复调用。"],"art":"data:image/svg+xml;base64,","caption":"定义 → 分类 → 比较 → 因果 → 决策：顺序微妙，且组合嵌套使用（《思考的真相》1.5）"},{"h3":"2选职业和选午饭，走的是同一条流水线","paras":["书里举了两个例子，一大一小。选职业：首先定义自己的兴趣和长处；然后分类可能的职业领域——科学、艺术、教育等等；接下来在这些领域当中比较，看看哪个更适合自己的需求和期望；最后考虑因果——在某个职业中工作，是否会带来满足感？收入是否足够多？四步走完，一个人才能做出明智的职业选择。","小到决定吃什么也一样：先定义健康饮食的标准（低热量、高营养价值）；再把食物分类成健康的和不健康的；然后在食物之间比较，挑出最符合标准的；最后想因果——这种食物对身体会产生什么影响。你看，事情有大小，流水线没有变。"],"art":"data:image/svg+xml;base64,","caption":"大到职业、小到午饭：每个决策都走一遍 定义→分类→比较→因果（《思考的真相》1.5）"},{"h3":"3拆一个真实决策：买一辆车","paras":["李笑来在书里拆了自己的一个真实决策：买特斯拉作为代步工具。买车这件事，是决策之后的行动；那当初如此决策的根据是什么？是因果关系——在此之前，他肯定根据自己的情况分析过、得出了结论，因为他比较过特斯拉和其他可能的选择，这是比较和因果的组合应用。","再往前退一步：在比较各款车之前，他肯定先在油车、电车里做出了一个选择——这是分类与比较的组合应用；而后在电车当中继续比较，根据比较的结果做出决定——这还是比较和因果的组合应用。一个\"买哪辆车\"，拆开来就是四要素来回接力。"],"art":"data:image/svg+xml;base64,","caption":"先分大类，再在类里比较，最后按比较结果决定——决策之后，才是行动（《思考的真相》1.5）"},{"h3":"4流水线的第一步，决定了终点","paras":["更有意思的是第二个决策：他不仅买了特斯拉的车，还买了特斯拉的股票。理由之一是：在他眼里，特斯拉从一开始就是一家机器人制造公司，而不是大多数人以为的汽车制造公司——他每天上路开的那辆车，是他这一生当中的第一个机器人，只不过不是人形机器人，而是车型机器人。定义不同，进而理解不同，而后分类和比较都不同，于是到最后决策自然不同。流水线的第一步变了，终点就完全不一样。","这样思考的当然不止他一个。同样是汽车，吉利控股集团的董事长李书福就有非常不一样的定义：\"汽车那不就是两张沙发配四个轮子，再加上一个铁壳儿吗？\"如此非同一般的定义，就很能解释他的一些非同一般的决策。这套由定义、分类、比较、因果构成的基础思考框架，非常简单且实用——所有的复杂问题，其实都是由这些简单的要素组合或者叠加构成的，于是，逐一突破即可。"],"art":"data:image/svg+xml;base64,","caption":"流水线第一步（定义）不同，终点（决策）就完全不同（《思考的真相》1.5）"}],"quote":"\"所有的复杂问题，其实都是由这些简单的要素组合或者叠加构成的。\"","quoteSrc":"—— 《思考的真相》1.5「决策」。每个决策＝定义→分类→比较→因果的组合应用；凡事从四要素出发，逐一突破即可。","reflect":[{"q":"回想你最近一次纠结的选择（报什么班、买哪个、周末先做什么）。对照流水线：你是从\"定义我到底要什么\"开始的，还是直接跳到了\"比较\"甚至\"随便选了\"？跳过的是哪一步？","hint":"没有标准答案，写在你自己的本子上。提示：多数纠结不是\"比不出来\"，而是第一步就没定义清楚\"我要的到底是什么\"——标准模糊，怎么比都乱。"},{"q":"李书福把汽车定义成\"两张沙发配四个轮子，再加上一个铁壳\"。挑一个你身边最普通的东西（书包、作业本、零花钱），试着给它一个不一样的定义——定义变了之后，你会做出什么不一样的决定？","hint":"没有标准答案。提示：比如把零花钱定义成\"种子\"而不是\"糖果券\"，接下来的分类（花掉的/种下的）和比较（哪个长得快）就全变了——决策也会跟着变。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周做一次\"四步决策\"实验：挑一个你真实要做的小决策（怎么安排周末、买哪样东西、选哪个活动），在本子上画四格，按顺序走完流水线：① 定义——我到底要什么？把标准写成一句毫无歧义的话；② 分类——有哪几类选项？查一下有没有漏掉的\"其他\"；③ 比较——同一范畴、相同属性地比，需要的话给依据打分；④ 因果——选了它，会带来什么？最后记录：过程中你有几次想跳过某一步直接选的冲动。周末把这张四格清单讲给家人听，对比\"直接选\"和\"走完四步\"的结果差多少。"},"32-cause-web":{"id":"32-cause-web","kicker":"成长读本 · 思考的真相","title":"世界不是一根因果链","hook":"有一组真实的统计：冰淇淋销量一增加，溺水的人数就增加；销量一减少，溺水人数也跟着减少。所以——冰淇淋会害人溺水？你大概立刻觉得不对劲。可为什么不对劲？前五篇你攒齐了定义、分类、比较、因果四样工具，这一篇往上走一层：这四样工具\"做\"出来的，其实是事物与事物之间的关系。而关系里最容易踩坑的一种，恰恰就是因果——它远比\"一个原因、一个结果\"要立体得多。","sections":[{"h3":"1关系不是看出来的，是\"做\"出来的","paras":["书里先给了一张地图：事物，是由定义描述清楚的；而分类、比较、因果分析这三个动作的完成，会确定事物与事物之间的关系。也就是说，每做一个动作，就\"产出\"几种关系。","分类之后，能确定从属与同属：苹果属于水果，是从属；香蕉也属于水果，还是从属；但苹果和香蕉之间是同属——它们都属于水果。同属的两个集合概念可能相交、可能不相交，相交的还能做与、或、非的计算：找\"既喜欢苹果又喜欢香蕉的人\"是与，要同时满足；找\"喜欢苹果或香蕉的人\"是或，满足其一即可；找\"不喜欢苹果的人\"是非，排除某个条件。","比较之后，能确定的关系只有两种：大于和约等于。小于只是大于的镜像（a 小于 b＝b 大于 a）；等于既然相等就无需比较；不等于则必属大于或约等于之一。而\"约等于\"对应着一种非常重要的思考模式——类比，书的第三部分会专门讲它。顺带一提，语文课上众多要素摆在一起时，基于比较产生的最常见逻辑关系是并列、递进与转折。"],"art":"data:image/svg+xml;base64,","caption":"定义描述事物；分类、比较、因果分析确定事物之间的关系（《思考的真相》2.1）"},{"h3":"2一起涨落，不等于谁害了谁","paras":["回到开头的冰淇淋。冰淇淋销量和溺水人数之间存在很强的相关关系：一个涨另一个也涨，一个跌另一个也跌。可你能说冰淇淋销量增加导致了溺水人数增加吗？不能。真相是：天气热了，冰淇淋销量就增加；与此同时，天气热了，去游泳的人就多了——就算溺水的比例不变，基数变大了，溺水人数也会增加。反过来天气凉了，两个数字一起回落。两件事其实都是\"天气变热\"这同一个原因造成的结果，它们之间根本不存在因果关系。","这个坑的代价很具体：如果把相关误解为因果，真正的原因就可能被忽略掉，成了漏网之鱼。再往下还有两层——很弱的相关，约等于无关：比如受教育程度高低和生活满意度之间，既没有真正的因果，也看不出明显的间接因果，准确讲干脆就是无关；更常见的是，人们把完全无关的两件事用因果硬连起来：比如早上烧了香、拜了佛，和下午股市上赚到了一点点钱。"],"art":"data:image/svg+xml;base64,","caption":"冰淇淋和溺水一起涨落，只因背后有同一个原因：天气热（《思考的真相》2.1）"},{"h3":"3人类盯着\"一因一果\"，盯了几千年","paras":["为什么这个坑这么多人踩？书里给了一个历史解释：研究因果关系事实上很难，仅靠感觉绝对不够用，从来都是耗时、费力、伤财的——在现代科学的启蒙阶段，大体上只有教堂里的神父和社会上的富二代，才有足够的生产资料去参与研究。于是在相当长的时间里，人们关注的只有一对一的因果关系：一个原因造成一个结果；看到一个结果，就去找\"那一个\"原因。","只关注一对一，最终发展成以为只有一对一——很多人不知不觉地相信\"有因必有果，有果必有因\"。而真实世界复杂得多：一个原因造成很多个结果——天热了，冰淇淋销量上升、溺水人数增加、社会耗电量也增加；一个结果对应很多个原因——溺水人数增加，可能是游泳的人多了，也可能那年有海啸，或者前一年安全教育培训减少了、相关支出被削减了。所以我们并非生活在一对一因果构成的一维因果世界里，而是生活在不知道比想象复杂多少倍的二维因果网络世界。"],"art":"data:image/svg+xml;base64,","caption":"一维因果链只是想象；真实世界是二维因果网络（《思考的真相》2.2）"},{"h3":"4互为因果，把时间请回了房间","paras":["网还不是终点。有一类关系，科学家直到上个世纪下半叶才有能力系统研究：互为因果。科技发展促进经济发展，反过来经济发展也促进科技发展。人们常说\"性格决定命运\"——这是典型的一维理解；实际上性格和命运互为因果：性格由过往的经历塑造，而命运就是经历的总和；同时性格又影响着决策，随时把\"现在\"变成\"过往\"，形成更多的经历。","互为因果的有趣之处在于：时间再也没办法被忽视了。一维思考里，时间只是个\"可能形成干扰的因素\"（先发生不保证是原因，上一篇讲过）。可在互为因果里，先是 a 导致 b，下一个瞬间 b 又导致 a，先后顺序不断对调——一个瞬间可以忽略，可无数个瞬间构成的是永恒，永恒如何忽略？时间就这样成了人们突然看见的房间里的大象。于是人类恍然大悟：我们所在的，是由时间穿起来的、无数个因果网络构成的三维因果系统世界。如果用\"十\"代表每个维度增加带来的复杂度变化，用一维眼光看三维世界，大约只能看到真实世界的千分之一——而实际的复杂度变化远不止十倍。时间在人类认知里走过了三步：干扰因素 → 必要且不可忽略 → 不可或缺的维度。"],"art":"data:image/svg+xml;base64,","caption":"从链到网，再到时间串起的系统——时间从干扰因素变成不可或缺的维度（《思考的真相》2.2）"}],"quote":"\"我们所存在的世界，并不是一维因果世界，也不是二维因果网络世界，而是由时间穿起来的、无数个因果网络构成的三维因果系统世界。\"","quoteSrc":"—— 《思考的真相》2.2「维度」。分类、比较、因果分析确定事物之间的关系；而因果这种关系，是一张被时间穿起来的网。","reflect":[{"q":"找一对你身边\"一起涨落\"的事：比如天冷了，感冒的人多了，热奶茶卖得也多了——热奶茶和感冒是什么关系？试着找出它们背后的\"天气热\"式共同原因。","hint":"没有标准答案，写在你自己的本子上。提示：先别问\"谁导致谁\"，先问\"有没有第三个东西，同时推着它们俩动\"——找到共同原因，相关和因果就分开了。"},{"q":"书里说性格和命运互为因果。在你自己身上找一对互为因果：比如\"越擅长打球就越爱打，越爱打练得越多，就更擅长\"。找到之后想想——如果想让这个循环转得更好，从哪一头动手最容易？","hint":"没有标准答案。提示：互为因果是个循环，没有\"唯一的起点\"；但循环里总有一头是你今天就能推一把的——推那一头，下一个瞬间它会替你推另一头。"}],"actionTitle":"🎯 行动卡 · 本周","action":"本周画一张\"因果网\"：挑一个你真实关心的结果（比如\"这周总是睡得晚\"\"这次数学进步了\"），在本子中央写下它，然后分四步织网：① 往左列出至少 3 个原因（别停在第一个）；② 挑其中一个原因，往右列出它造成的至少 3 个结果——验证\"一因多果\"；③ 在网里找出一对互为因果，用双向箭头 ⇄ 标出来；④ 周末把这张网讲给家人听，请他们再帮你补上几条你没画的线。最后数一数：这张网有几个节点、几条线——和你最初以为的\"一根链\"差多少。"},"33-analogy":{"id":"33-analogy","kicker":"成长读本 · 思考的真相","title":"约等号，是一座桥","hook":"老师讲地球的结构，先让你想一只鸡蛋：地壳像蛋壳，地幔像蛋清，地核像蛋黄——你一下子就懂了。过了几年讲原子，老师又让你先想太阳系：电子绕着原子核转，就像行星绕着太阳转——你又一下子懂了。奇怪：地球大到看不全，原子小到看不见，凭什么一\"比\"就明白？前面几篇你已经知道，比较能产出两种关系：大于，和约等于。这一篇讲的，就是\"约等于\"变成思考工具之后的样子——类比。","sections":[{"h3":"1大脑不够用？那就反过来找简单的","paras":["书的第三部分叫\"反璞\"。它开头先承认一个让人沮丧的事实：无论在一维因果世界、二维因果网络世界还是三维因果系统世界里，也无论是形式逻辑还是统计概率，普通人的大脑一直都不够用，从来就没够用过。那怎么办？反璞就可能是一个优势策略——面对越来越复杂的世界，反过来去找更简单、更容易的东西作为工具。","第一件简单工具就是类比。它的用法只有一步：为了理解陌生的 x，找来一个格外熟悉的 a，在 x 和 a 之间画一个约等号。然后，借助 a 的种种与 x 类似的属性，去理解 x 的各个方面。地球太大没法直接观测，就拿鸡蛋来比；原子太小没法直接观测，就拿早就学过的太阳系来比。类比，常常就这样跨越了已知和未知之间原本不可逾越的鸿沟。"],"art":"data:image/svg+xml;base64,","caption":"太大的、太小的、太陌生的，都能靠一个约等号从熟悉这头走过去（《思考的真相》3.1）"},{"h3":"2精彩的类比不多，值得专门收藏","paras":["精彩的类比事实上并不多，乃至于它们都值得收藏——作者自己就有一个专门的文件，用来记录遇到过的精彩类比。若干年来他最喜欢的有两个。第一个：教育就好像一副眼镜。戴上眼镜前后，你身处的是同一个世界；可戴上之后，就能把同样的世界看得更清楚。受教育前后也一样——世界没变，透过教育这块透镜，你把它看得更清楚、更透彻。第二个：科学由事实构成，正如房子由砖头构成。可仅仅把事实罗列出来并不构成科学——正如我们绝不会把一堆砖头直接称为房子。","类比还是作者与读者、讲者与听众互动的最佳手段。它不需要形式上的一问一答，却会让读者在脑子里主动思考、相互对话，甚至暗自惊叹\"果然如此\"。书里提到，在作品里把类比用得最频繁的人可能是钱钟书——从这个层面看，《围城》里每一段都有精彩精致的类比，可以算作一部最好的语文教材。"],"art":"data:image/svg+xml;base64,","caption":"收藏级类比的共同点：一句话，就让人暗自惊叹\"果然如此\"（《思考的真相》3.1）"},{"h3":"3桥会塌：当\"约等于\"被当成\"等于\"","paras":["类比最需要注意的地方只有一处：x 和 a 之间画的是约等号，而非等号。拿已知去类比未知，通常只能帮你理解 x 的某个或某些属性，而不是 x 本身或全部——它们只是局部类似，并非完全相同，也不可能全部类似。误把约等于理解为等于，会直接毁掉那座原本神奇的、可以从已知跨到未知的桥梁，让自己永远站在已知的这一侧，永无机会去探寻未知的另一侧。","书里给了两个真实的例子。Web2.0 刚崛起时，很多人听人讲了半天 Twitter 是什么，最后说：\"哦，我明白了，这不就是 QQ 签名吗？\"Web3.0 刚崛起时，听人讲了半天 Bitcoin，最后说：\"我明白了，这不就是数字黄金吗？\"一句\"这不就是……吗\"，把约等号焊死成了等号——新东西被塞回旧盒子，如此形成的理解障碍，往往是永远不可逾越的障碍。"],"art":"data:image/svg+xml;base64,","caption":"\"这不就是 QQ 签名 / 数字黄金吗\"——把 ≈ 当成 ＝，理解障碍就永远立在那里（《思考的真相》3.1）"},{"h3":"4反过来用：这个道理还能用在什么地方？","paras":["类比还有一个很少被人注意的用法。原本是为了理解陌生的 x 去找熟悉的 a；现在反过来：拿着已知的 a，去寻找并比较与之类似的 b、c、d、e，甚至 x。最常用的场景是——当你理解了一个道理之后，继续问自己一句：\"这个道理还能用在什么地方？\"很多道理是通用的，在这个领域适用，弄不好在别的领域也适用。这个反向应用，就是人们口中难得的能力：举一反三（也叫触类旁通、融会贯通、闻一知十、问羊知马）。","作者中学时代就在课堂上\"发呆\"练这个：几何课讲\"两条直线要么相交、要么平行，重合只是零距离平行\"——他想，每个人的时间都是一条直线，朋友要一起走很远，最关键的是相同的方向，否则即便相交也只交于一点，终将越来越远。物理课讲宇宙速度（7.8 km/s 绕轨道、11.2 km/s 冲出地球、16.7 km/s 飞出太阳系）——他想，赚钱速度也一样：到一定速度才自给自足，更高才摆脱生活束缚，再高才想去哪儿就去哪儿。牛顿说质量越大引力越大——他想，知识越多的人，吸引力越大。多年后创业找人，他用的是化学课的道理：特定元素按特定数量组合，才形成特定物质。上一篇的\"能并联一定并联\"，原本也是物理电路里的概念。","所谓\"聪明\"\"有灵气\"，听起来几近玄学；可穿过表象看实质，无非就是类比的反向应用——一个只要在意、肯学、肯练、肯攒，到最后谁都能掌握的小技能而已。"],"art":"data:image/svg+xml;base64,","caption":"举一反三＝类比的反向应用：肯学、肯练、肯攒，谁都能掌握（《思考的真相》3.1）"}],"quote":"\"类比，常常用来跨越已知和未知之间，那原本不可逾越的鸿沟。\"","quoteSrc":"—— 《思考的真相》3.1「类比」。为理解陌生的 x，找一个格外熟悉的 a，画一个约等号——但记住：是约等号，不是等号。","reflect":[{"q":"老师用鸡蛋讲地球、用太阳系讲原子。挑一个你最近学会的新东西，给它找一个\"格外熟悉的 a\"，把类比讲给家人听——然后想想：你这个类比在哪里\"只是约等于\"？哪里会失灵？","hint":"没有标准答案，写在你自己的本子上。提示：好类比要过两关——先问\"哪几个属性像\"，再问\"哪些属性其实不像\"。能说清\"哪里不像\"的人，才是真正会用类比的人。"},{"q":"作者把\"宇宙速度\"用到了赚钱上，把\"万有引力\"用到了知识上。挑一个你在某一科课堂上学过的道理，问一句\"这个道理还能用在什么地方\"——试着找出一个完全不同领域的新用法。","hint":"没有标准答案。提示：先把道理压缩成一句话（比如\"够快才能挣脱束缚\"），去掉学科专有名词，再拿这句话到生活里扫一圈——学习、交朋友、存零花钱，看它在哪儿也成立。"}],"actionTitle":"🎯 行动卡 · 本周","action":"作者有一个专门收藏精彩类比的文件——本周你也开一个\"类比收藏夹\"（本子上留一页就行）：① 收藏：留心课本、书和别人说的话，收集 3 个类比，每个记成\"x ≈ a，借了哪几个属性\"；② 验伪：给每个类比补一行\"哪里不像\"——找出它失灵的边界，防止把 ≈ 焊成 ＝；③ 反用：挑一个你已经懂的道理，问\"还能用在什么地方\"，写下 1 个跨领域的新用法；周末挑收藏夹里最得意的一条讲给家人听，看他们会不会说出那句\"果然如此\"。"}};
function getReader(id) { return CONTENT[id] || null; }
module.exports = { GROUPS, getReader };
